content:
我来帮你设计一个基于 Eino 最佳实践的 agent 项目。首先让我查看 Eino 的最佳实践和 agent 构建指南。根据 Eino 框架的最佳实践，我为你设计了一个完整的 agent 项目结构和代码：

## 项目结构

```
my-eino-agent/
├── cmd/
│   └── main.go                 # 主程序入口
├── internal/
│   ├── agent/
│   │   ├── agent.go            # Agent 创建和配置
│   │   └── runner.go           # Runner 配置和执行
│   ├── tools/
│   │   ├── tools.go            # 工具注册
│   │   ├── weather.go          # 天气查询工具
│   │   ├── calculator.go       # 计算器工具
│   │   └── search.go           # 搜索工具
│   ├── middleware/
│   │   └── middleware.go       # 自定义中间件
│   └── config/
│       └── config.go           # 配置管理
├── config/
│   └── config.yaml             # 配置文件
├── go.mod
└── go.sum
```

## 完整代码

### 1. go.mod

```go
module my-eino-agent

go 1.22

require (
    github.com/cloudwego/eino v0.3.6
    github.com/cloudwego/eino-ext/components/model/openai v0.0.0-20241226031725-3c9bb2c1c97d
    github.com/cloudwego/eino-ext/adk/backend/local v0.0.0-20241226031725-3c9bb2c1c97d
    gopkg.in/yaml.v3 v3.0.1
)
```

### 2. config/config.yaml

```yaml
agent:
  name: "SmartAssistant"
  description: "An intelligent assistant with weather, calculator, and search capabilities"
  instruction: |
    You are a helpful AI assistant. 
    Use the available tools to help users with their requests.
    Always be polite and provide detailed explanations.
  max_iterations: 20

model:
  provider: "openai"
  model_name: "gpt-4o"
  api_key: "${OPENAI_API_KEY}"  # 从环境变量读取
  temperature: 0.7

middleware:
  filesystem:
    enabled: true
    base_dir: "./workspace"
  summarization:
    enabled: true
    context_tokens: 190000
  reduction:
    enabled: true
    max_tokens: 128000

server:
  enable_streaming: true
  log_level: "info"
```

### 3. internal/config/config.go

```go
package config

import (
	"os"
	"strings"

	"gopkg.in/yaml.v3"
)

type Config struct {
	Agent      AgentConfig      `yaml:"agent"`
	Model      ModelConfig      `yaml:"model"`
	Middleware MiddlewareConfig `yaml:"middleware"`
	Server     ServerConfig     `yaml:"server"`
}

type AgentConfig struct {
	Name          string `yaml:"name"`
	Description   string `yaml:"description"`
	Instruction   string `yaml:"instruction"`
	MaxIterations int    `yaml:"max_iterations"`
}

type ModelConfig struct {
	Provider    string  `yaml:"provider"`
	ModelName   string  `yaml:"model_name"`
	APIKey      string  `yaml:"api_key"`
	Temperature float32 `yaml:"temperature"`
}

type MiddlewareConfig struct {
	Filesystem    FilesystemMiddlewareConfig    `yaml:"filesystem"`
	Summarization SummarizationMiddlewareConfig `yaml:"summarization"`
	Reduction     ReductionMiddlewareConfig     `yaml:"reduction"`
}

type FilesystemMiddlewareConfig struct {
	Enabled bool   `yaml:"enabled"`
	BaseDir string `yaml:"base_dir"`
}

type SummarizationMiddlewareConfig struct {
	Enabled       bool `yaml:"enabled"`
	ContextTokens int  `yaml:"context_tokens"`
}

type ReductionMiddlewareConfig struct {
	Enabled    bool `yaml:"enabled"`
	MaxTokens  int  `yaml:"max_tokens"`
}

type ServerConfig struct {
	EnableStreaming bool   `yaml:"enable_streaming"`
	LogLevel        string `yaml:"log_level"`
}

func Load(path string) (*Config, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		return nil, err
	}

	// 展开环境变量
	content := os.ExpandEnv(string(data))

	var cfg Config
	if err := yaml.Unmarshal([]byte(content), &cfg); err != nil {
		return nil, err
	}

	// 处理 API Key（支持 ${VAR} 格式）
	if strings.HasPrefix(cfg.Model.APIKey, "${") && strings.HasSuffix(cfg.Model.APIKey, "}") {
		envVar := cfg.Model.APIKey[2 : len(cfg.Model.APIKey)-1]
		cfg.Model.APIKey = os.Getenv(envVar)
	}

	return &cfg, nil
}
```

