}

// NewWeatherTool 创建天气查询工具
func NewWeatherTool() (tool.BaseTool, error) {
	return utils.InferTool(
		"get_weather",
		"查询指定城市的天气信息，包括温度、天气状况和湿度",
		func(ctx context.Context, input *WeatherInput) (*WeatherOutput, error) {
			// 这里是模拟实现，实际应用中应调用真实的天气 API
			weatherData := map[string]*WeatherOutput{
				"北京": {
					City:        "北京",
					Temperature: "22°C",
					Weather:     "晴",
					Humidity:    "45%",
				},
				"上海": {
					City:        "上海",
					Temperature: "26°C",
					Weather:     "多云",
					Humidity:    "65%",
				},
				"东京": {
					City:        "东京",
					Temperature: "24°C",
					Weather:     "晴转多云",
					Humidity:    "55%",
				},
			}

			if result, ok := weatherData[input.City]; ok {
				return result, nil
			}

			// 默认返回模拟数据
			return &WeatherOutput{
				City:        input.City,
				Temperature: "25°C",
				Weather:     "晴",
				Humidity:    "50%",
			}, nil
		},
	)
}
