### 5. internal/tools/calculator.go

```go
package tools

import (
	"context"
	"fmt"
	"strconv"
	"strings"

	"github.com/cloudwego/eino/components/tool"
	"github.com/cloudwego/eino/components/tool/utils"
)

// CalculatorInput 计算器工具输入
type CalculatorInput struct {
	Expression string `json:"expression" jsonschema_description:"数学表达式，如：2+3*4、(10+5)/3"`
}

// CalculatorOutput 计算器工具输出
type CalculatorOutput struct {
	Expression string  `json:"expression"`
	Result     float64 `json:"result"`
}

// NewCalculatorTool 创建计算器工具
func NewCalculatorTool() (tool.BaseTool, error) {
	return utils.InferTool(
		"calculator",
		"执行数学计算，支持加减乘除和括号运算",
		func(ctx context.Context, input *CalculatorInput) (*CalculatorOutput, error) {
			// 简单的计算器实现（仅演示用，实际应用建议使用更完善的数学表达式解析库）
			result, err := evaluateExpression(input.Expression)
			if err != nil {
				return nil, fmt.Errorf("计算表达式失败: %w", err)
			}

			return &CalculatorOutput{
				Expression: input.Expression,
				Result:     result,
			}, nil
		},
	)
}

// evaluateExpression 简单表达式求值（仅支持基本运算）
func evaluateExpression(expr string) (float64, error) {
	// 移除空格
	expr = strings.ReplaceAll(expr, " ", "")

	// 简单实现：仅处理加法（演示用）
	// 实际应用中建议使用 github.com/Knetic/govaluate 等库
	if strings.Contains(expr, "+") {
		parts := strings.Split(expr, "+")
		if len(parts) == 2 {
			a, err1 := strconv.ParseFloat(parts[0], 64)
			b, err2 := strconv.ParseFloat(parts[1], 64)
			if err1 != nil || err2 != nil {
				return 0, fmt.Errorf("invalid expression")
			}
			return a + b, nil
		}
	}

	if strings.Contains(expr, "*") {
		parts := strings.Split(expr, "*")
		if len(parts) == 2 {
			a, err1 := strconv.ParseFloat(parts[0], 64)
			b, err2 := strconv.ParseFloat(parts[1], 64)
			if err1 != nil || err2 != nil {
				return 0, fmt.Errorf("invalid expression")
			}
			return a * b, nil
		}
	}

	// 尝试解析为数字
	return strconv.ParseFloat(expr, 64)
}
```

### 6. internal/tools/search.go

```go
package tools

import (
	"context"
	"fmt"

	"github.com/cloudwego/eino/components/tool"
	"github.com/cloudwego/eino/components/tool/utils"
)

// SearchInput 搜索工具输入
type SearchInput struct {
	Query string `json:"query" jsonschema_description:"搜索查询内容"`
	Limit int    `json:"limit" jsonschema_description:"返回结果数量限制，默认为5"`
}

// SearchResult 搜索结果
type SearchResult struct {
	Title   string `json:"title"`
	URL     string `json:"url"`
	Summary string `json:"summary"`
}

// SearchOutput 搜索工具输出
type SearchOutput struct {
	Query   string        `json:"query"`
	Results []SearchResult `json:"results"`
}

// NewSearchTool 创建搜索工具
func NewSearchTool() (tool.BaseTool, error) {
	return utils.InferTool(
		"web_search",
		"搜索互联网获取信息",
		func(ctx context.Context, input *SearchInput) (*SearchOutput, error) {
			// 模拟搜索结果
			if input.Limit <= 0 {
				input.Limit = 5
			}

			// 这里是模拟实现，实际应用中应调用真实的搜索 API
			results := []SearchResult{
				{
					Title:   fmt.Sprintf("关于 %s 的详细信息", input.Query),
					URL:     "https://example.com/result1",
					Summary: fmt.Sprintf("这是关于 %s 的详细信息和解释...", input.Query),
				},
				{
					Title:   fmt.Sprintf("%s - 维基百科", input.Query),
					URL:     "https://wikipedia.org/example",
					Summary: fmt.Sprintf("%s 的定义、历史和相关背景...", input.Query),
				},
			}

			if len(results) > input.Limit {
				results = results[:input.Limit]
			}

			return &SearchOutput{
				Query:   input.Query,
				Results: results,
			}, nil
		},
	)
}
