### 7. internal/tools/tools.go

```go
package tools

import (
	"github.com/cloudwego/eino/components/tool"
)

// Registry 工具注册表
type Registry struct {
	tools []tool.BaseTool
}

// NewRegistry 创建工具注册表
func NewRegistry() *Registry {
	return &Registry{
		tools: make([]tool.BaseTool, 0),
	}
}

// Register 注册工具
func (r *Registry) Register(t tool.BaseTool) {
	r.tools = append(r.tools, t)
}

// GetAll 获取所有工具
func (r *Registry) GetAll() []tool.BaseTool {
	return r.tools
}

// InitTools 初始化所有内置工具
func InitTools() ([]tool.BaseTool, error) {
	registry := NewRegistry()

	// 注册天气工具
	weatherTool, err := NewWeatherTool()
	if err != nil {
		return nil, fmt.Errorf("failed to create weather tool: %w", err)
	}
	registry.Register(weatherTool)

	// 注册计算器工具
	calcTool, err := NewCalculatorTool()
	if err != nil {
		return nil, fmt.Errorf("failed to create calculator tool: %w", err)
	}
	registry.Register(calcTool)

	// 注册搜索工具
	searchTool, err := NewSearchTool()
	if err != nil {
		return nil, fmt.Errorf("failed to create search tool: %w", err)
	}
	registry.Register(searchTool)

	return registry.GetAll(), nil
}
```

### 8. internal/middleware/middleware.go

```go
package middleware

import (
	"context"

	"github.com/cloudwego/eino-ext/adk/backend/local"
	"github.com/cloudwego/eino/adk"
	"github.com/cloudwego/eino/adk/middlewares/filesystem"
	"github.com/cloudwego/eino/adk/middlewares/reduction"
	"github.com/cloudwego/eino/adk/middlewares/summarization"
	"github.com/cloudwego/eino/components/model"

	"my-eino-agent/internal/config"
)

// SetupMiddlewares 设置中间件
func SetupMiddlewares(ctx context.Context, cfg *config.Config, summaryModel model.BaseChatModel) ([]adk.ChatModelAgentMiddleware, error) {
	var middlewares []adk.ChatModelAgentMiddleware

	// 1. 文件系统中间件（可选）
	if cfg.Middleware.Filesystem.Enabled {
		fsBackend, err := local.NewBackend(ctx, &local.Config{
			RootPath: cfg.Middleware.Filesystem.BaseDir,
		})
		if err != nil {
			return nil, err
		}

		fsMW, err := filesystem.New(ctx, &filesystem.MiddlewareConfig{
			Backend: fsBackend,
		})
		if err != nil {
			return nil, err
		}
		middlewares = append(middlewares, fsMW)
	}

	// 2. 总结中间件（压缩长对话历史）
	if cfg.Middleware.Summarization.Enabled && summaryModel != nil {
		sumMW, err := summarization.New(ctx, &summarization.Config{
			Model: summaryModel,
			Trigger: &summarization.TriggerCondition{
				ContextTokens: cfg.Middleware.Summarization.ContextTokens,
			},
		})
		if err != nil {
			return nil, err
		}
		middlewares = append(middlewares, sumMW)
	}

	// 3. 缩减中间件（处理大型工具结果）
	if cfg.Middleware.Reduction.Enabled {
		// 需要一个 backend 来存储被裁剪的内容
		reductionBackend, err := local.NewBackend(ctx, &local.Config{
			RootPath: "./.reduction_cache",
		})
		if err != nil {
			return nil, err
		}

		redMW, err := reduction.New(ctx, &reduction.Config{
			Backend:       reductionBackend,
			MaxTokensForClear: cfg.Middleware.Reduction.MaxTokens,
		})
		if err != nil {
			return nil, err
		}
		middlewares = append(middlewares, redMW)
	}

	return middlewares, nil
}
```

### 9. internal/agent/agent.go

```go
package agent

import (
	"context"
	"fmt"

	"github.com/cloudwego/eino-ext/components/model/openai"
	"github.com/cloudwego/eino/adk"
	"github.com/cloudwego/eino/components/tool"
	"github.com/cloudwego/eino/compose"

	"my-eino-agent/internal/config"
	"my-eino-agent/internal/middleware"
	"my-eino-agent/internal/tools"
)

// Builder Agent 构建器
type Builder struct {
	cfg    *config.Config
	model  *openai.ChatModel
	tools  []tool.BaseTool
}

// NewBuilder 创建 Agent 构建器
func NewBuilder(cfg *config.Config) *Builder {
	return &Builder{
		cfg:   cfg,
		tools: make([]tool.BaseTool, 0),
	}
}

// InitModel 初始化模型
func (b *Builder) InitModel(ctx context.Context) error {
	model, err := openai.NewChatModel(ctx, &openai.ChatModelConfig{
		Model:       b.cfg.Model.ModelName,
		APIKey:      b.cfg.Model.APIKey,
		Temperature: b.cfg.Model.Temperature,
	})
	if err != nil {
		return fmt.Errorf("failed to initialize model: %w", err)
	}

	b.model = model
	return nil
}

// InitTools 初始化工具
func (b *Builder) InitTools() error {
	allTools, err := tools.InitTools()
	if err != nil {
		return fmt.Errorf("failed to initialize tools: %w", err)
	}

	b.tools = allTools
	return nil
}

// Build 构建 Agent
func (b *Builder) Build(ctx context.Context) (adk.Agent, error) {
	// 设置中间件
	middlewares, err := middleware.SetupMiddlewares(ctx, b.cfg, b.model)
	if err != nil {
		return nil, fmt.Errorf("failed to setup middlewares: %w", err)
	}

	// 创建 Agent 配置
	agentConfig := &adk.ChatModelAgentConfig{
		Name:        b.cfg.Agent.Name,
		Description: b.cfg.Agent.Description,
		Instruction: b.cfg.Agent.Instruction,
		Model:       b.model,
		ToolsConfig: adk.ToolsConfig{
			ToolsNodeConfig: compose.ToolsNodeConfig{
				Tools: b.tools,
			},
		},
		MaxIterations: b.cfg.Agent.MaxIterations,
		Handlers:      middlewares,
	}

	// 创建 Agent
	agent, err := adk.NewChatModelAgent(ctx, agentConfig)
	if err != nil {
		return nil, fmt.Errorf("failed to create agent: %w", err)
	}

	return agent, nil
}
```

### 10. internal/agent/runner.go

```go
package agent

import (
	"context"
	"fmt"
	"io"
	"log"

	"github.com/cloudwego/eino/adk"
	"github.com/cloudwego/eino/schema"

	"my-eino-agent/internal/config"
)

// Runner 封装的 Agent Runner
type Runner struct {
	runner *adk.Runner
	cfg    *config.Config
}

// NewRunner 创建 Runner
func NewRunner(cfg *config.Config, agent adk.Agent) *Runner {
	return &Runner{
		runner: adk.NewRunner(context.Background(), adk.RunnerConfig{
			Agent:           agent,
			EnableStreaming: cfg.Server.EnableStreaming,
		}),
		cfg: cfg,
	}
}

// Query 执行查询（便捷方法，用于单个用户消息）
func (r *Runner) Query(ctx context.Context, query string) error {
	fmt.Printf("\n用户: %s\n", query)
	fmt.Println("助手: ", end="")

	iter := r.runner.Query(ctx, query)

	return r.processIterator(iter)
}

// Run 执行完整的消息列表
func (r *Runner) Run(ctx context.Context, messages []*schema.Message) error {
	iter := r.runner.Run(ctx, messages)
	return r.processIterator(iter)
}

// processIterator 处理迭代器输出
func (r *Runner) processIterator(iter *adk.AsyncIterator[*adk.AgentEvent]) error {
	for {
		event, ok := iter.Next()
		if !ok {
			break
		}

		if event.Err != nil {
			return fmt.Errorf("agent error: %w", event.Err)
		}

		// 处理不同类型的事件
		if event.Output != nil && event.Output.MessageOutput != nil {
			mv := event.Output.MessageOutput

			if mv.IsStreaming && r.cfg.Server.EnableStreaming {
				// 流式输出
				for {
					msg, err := mv.MessageStream.Recv()
					if err == io.EOF {
						break
					}
					if err != nil {
						return fmt.Errorf("stream error: %w", err)
					}

					fmt.Print(msg.Content)
				}
				fmt.Println()
			} else {
				// 非流式输出
				fmt.Printf("[%s] %s\n", mv.Role, mv.Message.Content)
			}
		}

		// 可以处理其他类型的事件，如工具调用等
		if event.Output != nil && event.Output.ToolCallOutput != nil {
			tco := event.Output.ToolCallOutput
			log.Printf("[工具调用] %s -> %s", tco.ToolName, tco.Result)
		}
	}

	return nil
}
```

### 11. cmd/main.go

```go
package main

import (
	"bufio"
	"context"
	"fmt"
	"log"
	"os"
	"strings"

	"my-eino-agent/internal/agent"
	"my-eino-agent/internal/config"
)

func main() {
	ctx := context.Background()

	// 1. 加载配置
	cfg, err := config.Load("./config/config.yaml")
	if err != nil {
		log.Fatalf("加载配置失败: %v", err)
	}

	fmt.Println("========================================")
	fmt.Printf("  %s 启动中...\n", cfg.Agent.Name)
	fmt.Println("========================================")

	// 2. 构建 Agent
	builder := agent.NewBuilder(cfg)

	// 初始化模型
	if err := builder.InitModel(ctx); err != nil {
		log.Fatalf("初始化模型失败: %v", err)
	}

	// 初始化工具
	if err := builder.InitTools(); err != nil {
		log.Fatalf("初始化工具失败: %v", err)
	}

	// 构建 Agent
	ag, err := builder.Build(ctx)
	if err != nil {
		log.Fatalf("构建 Agent 失败: %v", err)
	}

	// 3. 创建 Runner
	runner := agent.NewRunner(cfg, ag)

	fmt.Println("\n助手已就绪，输入消息开始对话（输入 'quit' 退出）：")
	fmt.Println("----------------------------------------")

	// 4. 交互式对话循环
	scanner := bufio.NewScanner(os.Stdin)
	for {
		fmt.Print("\n用户: ")
		if !scanner.Scan() {
			break
		}

		input := strings.TrimSpace(scanner.Text())
		if input == "" {
			continue
		}

		// 退出命令
		if strings.ToLower(input) == "quit" || strings.ToLower(input) == "exit" {
			fmt.Println("\n再见！")
			break
		}

		// 执行查询
		if err := runner.Query(ctx, input); err != nil {
			log.Printf("查询失败: %v", err)
		}
	}

	if err := scanner.Err(); err != nil {
		log.Fatalf("读取输入错误: %v", err)
	}
}
```

## 运行方式

```bash
# 1. 设置环境变量
export OPENAI_API_KEY="your-api-key"

# 2. 创建工作目录
mkdir -p workspace

# 3. 运行项目
go run cmd/main.go
```

## 关键设计说明

1. **分层架构**：清晰的目录结构，`cmd`、`internal`、`config` 各司其职
2. **配置管理**：支持 YAML 配置文件和环境变量
3. **工具模块化**：每个工具独立文件，通过 Registry 统一管理
4. **中间件链**：按最佳实践顺序配置中间件（文件系统 → 总结 → 缩减）
5. **流式支持**：Runner 支持流式和非流式两种模式
6. **错误处理**：统一的错误处理和日志记录

这个项目结构遵循了 Go 的标准项目布局和 Eino 的最佳实践，可以直接使用或作为模板进行扩展。

