```go
package session

import (
	"bytes"
	"context"
	"encoding/gob"
	"strings"
	"sync"

	"github.com/cloudwego/eino/schema"
)

// Store 定义会话存储接口
type Store interface {
	// Write 保存会话消息
	Write(ctx context.Context, sessionID string, msgs []*schema.Message) error
	// Read 读取会话消息
	Read(ctx context.Context, sessionID string) ([]*schema.Message, error)
	// Delete 删除会话
	Delete(ctx context.Context, sessionID string) error
	// Query 查询包含特定文本的消息
	Query(ctx context.Context, sessionID, text string, limit int) ([]*schema.Message, error)
}

// EncodeMessages 序列化消息
func EncodeMessages(msgs []*schema.Message) ([]byte, error) {
	var buf bytes.Buffer
	enc := gob.NewEncoder(&buf)
	if err := enc.Encode(msgs); err != nil {
		return nil, err
	}
	return buf.Bytes(), nil
}

// DecodeMessages 反序列化消息
func DecodeMessages(b []byte) ([]*schema.Message, error) {
	if len(b) == 0 {
		return nil, nil
	}
	dec := gob.NewDecoder(bytes.NewReader(b))
	var msgs []*schema.Message
	if err := dec.Decode(&msgs); err != nil {
		return nil, err
	}
	return msgs, nil
}

// InMemoryStore 内存存储实现（适合开发/测试）
type InMemoryStore struct {
	mu   sync.RWMutex
	data map[string][]byte
}

// NewInMemoryStore 创建内存存储
func NewInMemoryStore() *InMemoryStore {
	return &InMemoryStore{data: make(map[string][]byte)}
}

func (s *InMemoryStore) Write(ctx context.Context, sessionID string, msgs []*schema.Message) error {
	b, err := EncodeMessages(msgs)
	if err != nil {
		return err
	}
	s.mu.Lock()
	s.data[sessionID] = b
	s.mu.Unlock()
	return nil
}

func (s *InMemoryStore) Read(ctx context.Context, sessionID string) ([]*schema.Message, error) {
	s.mu.RLock()
	b := s.data[sessionID]
	s.mu.RUnlock()
	return DecodeMessages(b)
}

func (s *InMemoryStore) Delete(ctx context.Context, sessionID string) error {
	s.mu.Lock()
	delete(s.data, sessionID)
	s.mu.Unlock()
	return nil
}

func (s *InMemoryStore) Query(ctx context.Context, sessionID, text string, limit int) ([]*schema.Message, error) {
	msgs, err := s.Read(ctx, sessionID)
	if err != nil {
		return nil, err
	}
	if len(msgs) == 0 || text == "" {
		return nil, nil
	}
	q := strings.ToLower(text)
	out := make([]*schema.Message, 0, limit)
	for _, m := range msgs {
		if m == nil {
			continue
		}
		if strings.Contains(strings.ToLower(m.Content), q) {
			out = append(out, m)
			if limit > 0 && len(out) >= limit {
				break
			}
		}
	}
	return out, nil
}
