### 2. internal/session/manager.go

```go
package session

import (
	"context"
	"fmt"
	"log"
	"sync"
	"time"

	"github.com/cloudwego/eino/schema"
)

// Session 表示一个会话
type Session struct {
	ID        string
	Messages  []*schema.Message
	CreatedAt time.Time
	UpdatedAt time.Time
	Metadata  map[string]any
}

// Manager 会话管理器
type Manager struct {
	store       Store
	sessions    map[string]*Session
	mu          sync.RWMutex
	maxHistory  int // 最大历史消息数（0 表示无限制）
}

// ManagerConfig 会话管理器配置
type ManagerConfig struct {
	Store      Store
	MaxHistory int // 保留最近 N 条消息，0 表示无限制
}

// NewManager 创建会话管理器
func NewManager(cfg *ManagerConfig) *Manager {
	if cfg.Store == nil {
		cfg.Store = NewInMemoryStore()
	}
	return &Manager{
		store:      cfg.Store,
		sessions:   make(map[string]*Session),
		maxHistory: cfg.MaxHistory,
	}
}

// GetOrCreate 获取或创建会话
func (m *Manager) GetOrCreate(ctx context.Context, sessionID string) (*Session, error) {
	m.mu.Lock()
	defer m.mu.Unlock()

	// 先检查内存缓存
	if sess, ok := m.sessions[sessionID]; ok {
		return sess, nil
	}

	// 从存储加载
	msgs, err := m.store.Read(ctx, sessionID)
	if err != nil {
		log.Printf("Warning: failed to read session from store: %v", err)
		msgs = nil
	}

	sess := &Session{
		ID:        sessionID,
		Messages:  msgs,
		CreatedAt: time.Now(),
		UpdatedAt: time.Now(),
		Metadata:  make(map[string]any),
	}
	m.sessions[sessionID] = sess
	return sess, nil
}

// AddMessage 添加消息到会话
func (m *Manager) AddMessage(ctx context.Context, sessionID string, msg *schema.Message) error {
	m.mu.Lock()
	defer m.mu.Unlock()

	sess, ok := m.sessions[sessionID]
	if !ok {
		return fmt.Errorf("session %s not found", sessionID)
	}

	sess.Messages = append(sess.Messages, msg)
	sess.UpdatedAt = time.Now()

	// 应用历史消息限制
	if m.maxHistory > 0 && len(sess.Messages) > m.maxHistory {
		sess.Messages = sess.Messages[len(sess.Messages)-m.maxHistory:]
	}

	return nil
}

// AddMessages 批量添加消息
func (m *Manager) AddMessages(ctx context.Context, sessionID string, msgs []*schema.Message) error {
	m.mu.Lock()
	defer m.mu.Unlock()

	sess, ok := m.sessions[sessionID]
	if !ok {
		return fmt.Errorf("session %s not found", sessionID)
	}

	sess.Messages = append(sess.Messages, msgs...)
	sess.UpdatedAt = time.Now()

	// 应用历史消息限制
	if m.maxHistory > 0 && len(sess.Messages) > m.maxHistory {
		sess.Messages = sess.Messages[len(sess.Messages)-m.maxHistory:]
	}

	return nil
}

// GetMessages 获取会话的所有消息
func (m *Manager) GetMessages(ctx context.Context, sessionID string) ([]*schema.Message, error) {
	m.mu.RLock()
	defer m.mu.RUnlock()

	sess, ok := m.sessions[sessionID]
	if !ok {
		return nil, fmt.Errorf("session %s not found", sessionID)
	}

	// 返回副本
	result := make([]*schema.Message, len(sess.Messages))
	copy(result, sess.Messages)
	return result, nil
}

// Save 持久化会话到存储
func (m *Manager) Save(ctx context.Context, sessionID string) error {
	m.mu.RLock()
	defer m.mu.RUnlock()

	sess, ok := m.sessions[sessionID]
	if !ok {
		return fmt.Errorf("session %s not found", sessionID)
	}

	return m.store.Write(ctx, sessionID, sess.Messages)
}

// Clear 清除会话（内存和存储）
func (m *Manager) Clear(ctx context.Context, sessionID string) error {
	m.mu.Lock()
	defer m.mu.Unlock()

	delete(m.sessions, sessionID)
	return m.store.Delete(ctx, sessionID)
}

// List 列出所有活跃会话
func (m *Manager) List() []string {
	m.mu.RLock()
	defer m.mu.RUnlock()

	ids := make([]string, 0, len(m.sessions))
	for id := range m.sessions {
		ids = append(ids, id)
	}
	return ids
}
