package agent

import (
	"context"
	"fmt"
	"io"
	"log"

	"github.com/cloudwego/eino/adk"
	"github.com/cloudwego/eino/schema"

	"my-eino-agent/internal/config"
	"my-eino-agent/internal/session"
)

// Runner 封装的 Agent Runner（支持会话存储）
type Runner struct {
	runner   *adk.Runner
	cfg      *config.Config
	sessions *session.Manager
}

// NewRunner 创建 Runner
func NewRunner(cfg *config.Config, agent adk.Agent, sessionManager *session.Manager) *Runner {
	return &Runner{
		runner: adk.NewRunner(context.Background(), adk.RunnerConfig{
			Agent:           agent,
			EnableStreaming: cfg.Server.EnableStreaming,
		}),
		cfg:      cfg,
		sessions: sessionManager,
	}
}

// Query 执行查询（支持会话历史）
func (r *Runner) Query(ctx context.Context, sessionID, query string) error {
	fmt.Printf("\n[Session: %s]\n", sessionID)
	fmt.Printf("用户: %s\n", query)

	// 1. 获取或创建会话
	sess, err := r.sessions.GetOrCreate(ctx, sessionID)
	if err != nil {
		return fmt.Errorf("failed to get session: %w", err)
	}

	// 2. 构建完整的消息历史（历史 + 新消息）
	history := sess.Messages
	userMsg := schema.UserMessage(query)
	allMsgs := append(history, userMsg)

	// 3. 执行 Agent
	iter := r.runner.Run(ctx, allMsgs)

	// 4. 收集输出消息（用于保存历史）
	var producedMsgs []*schema.Message
	producedMsgs = append(producedMsgs, userMsg) // 用户消息也要保存

	// 5. 处理迭代器输出
	fmt.Print("助手: ")
	for {
		event, ok := iter.Next()
		if !ok {
			break
		}

		if event.Err != nil {
			return fmt.Errorf("agent error: %w", event.Err)
		}

		// 处理消息输出
		if event.Output != nil && event.Output.MessageOutput != nil {
			mv := event.Output.MessageOutput

			if mv.IsStreaming && r.cfg.Server.EnableStreaming {
				// 流式输出
				var chunks []*schema.Message
				for {
					msg, err := mv.MessageStream.Recv()
					if err == io.EOF {
						break
					}
					if err != nil {
						return fmt.Errorf("stream error: %w", err)
					}
					fmt.Print(msg.Content)
					chunks = append(chunks, msg)
				}
				fmt.Println()

				// 合并流式消息
				if fullMsg, err := schema.ConcatMessages(chunks); err == nil && fullMsg != nil {
					producedMsgs = append(producedMsgs, fullMsg)
				}
			} else {
				// 非流式输出
				fmt.Printf("[%s] %s\n", mv.Role, mv.Message.Content)
				producedMsgs = append(producedMsgs, mv.Message)
			}
		}

		// 记录工具调用（可选）
		if event.Output != nil && event.Output.ToolCallOutput != nil {
			tco := event.Output.ToolCallOutput
			log.Printf("[工具调用] %s", tco.ToolName)
		}
	}

	// 6. 保存消息到会话
	if err := r.sessions.AddMessages(ctx, sessionID, producedMsgs); err != nil {
		log.Printf("Warning: failed to add messages to session: %v", err)
	}

	// 7. 持久化会话
	if err := r.sessions.Save(ctx, sessionID); err != nil {
		log.Printf("Warning: failed to save session: %v", err)
	}

	return nil
}

// Run 执行完整的消息列表（高级用法）
func (r *Runner) Run(ctx context.Context, sessionID string, messages []*schema.Message) error {
	// 获取历史
	sess, err := r.sessions.GetOrCreate(ctx, sessionID)
	if err != nil {
		return err
	}

	// 合并历史
	allMsgs := append(sess.Messages, messages...)

	// 执行
	iter := r.runner.Run(ctx, allMsgs)

	// 处理输出并收集消息
	var producedMsgs []*schema.Message
	producedMsgs = append(producedMsgs, messages...)

	for {
		event, ok := iter.Next()
		if !ok {
			break
		}

		if event.Err != nil {
			return event.Err
		}

		if event.Output != nil && event.Output.MessageOutput != nil {
			mv := event.Output.MessageOutput
			msg, err := mv.GetMessage()
			if err != nil {
				continue
			}
			producedMsgs = append(producedMsgs, msg)
		}
	}

	// 保存
	r.sessions.AddMessages(ctx, sessionID, producedMsgs)
	return r.sessions.Save(ctx, sessionID)
}

// GetSessionHistory 获取会话历史
func (r *Runner) GetSessionHistory(ctx context.Context, sessionID string) ([]*schema.Message, error) {
	return r.sessions.GetMessages(ctx, sessionID)
}

// ClearSession 清除会话
func (r *Runner) ClearSession(ctx context.Context, sessionID string) error {
	return r.sessions.Clear(ctx, sessionID)
}

// ListSessions 列出所有会话
func (r *Runner) ListSessions() []string {
	return r.sessions.List()
}
