package main

import (
	"bufio"
	"context"
	"fmt"
	"log"
	"os"
	"strings"

	"my-eino-agent/internal/agent"
	"my-eino-agent/internal/config"
	"my-eino-agent/internal/session"
)

func main() {
	ctx := context.Background()

	// 1. 加载配置
	cfg, err := config.Load("./config/config.yaml")
	if err != nil {
		log.Fatalf("加载配置失败: %v", err)
	}

	fmt.Println("========================================")
	fmt.Printf("  %s 启动中...\n", cfg.Agent.Name)
	fmt.Println("========================================")

	// 2. 构建会话管理器
	sessionManager := session.NewManager(&session.ManagerConfig{
		Store:      session.NewInMemoryStore(), // 生产环境可替换为 Redis 等
		MaxHistory: 50,                         // 保留最近 50 条消息
	})

	// 3. 构建 Agent
	builder := agent.NewBuilder(cfg)

	if err := builder.InitModel(ctx); err != nil {
		log.Fatalf("初始化模型失败: %v", err)
	}

	if err := builder.InitTools(); err != nil {
		log.Fatalf("初始化工具失败: %v", err)
	}

	ag, err := builder.Build(ctx)
	if err != nil {
		log.Fatalf("构建 Agent 失败: %v", err)
	}

	// 4. 创建 Runner（注入会话管理器）
	runner := agent.NewRunner(cfg, ag, sessionManager)

	fmt.Println("\n助手已就绪！")
	fmt.Println("命令:")
	fmt.Println("  /new <session_id>  - 创建/切换会话")
	fmt.Println("  /history           - 查看当前会话历史")
	fmt.Println("  /list              - 列出所有会话")
	fmt.Println("  /clear             - 清除当前会话")
	fmt.Println("  /quit              - 退出程序")
	fmt.Println("----------------------------------------")

	// 默认会话
	currentSession := "default"

	// 5. 交互式对话循环
	scanner := bufio.NewScanner(os.Stdin)
	for {
		fmt.Printf("\n[%s] > ", currentSession)
		if !scanner.Scan() {
			break
		}

		input := strings.TrimSpace(scanner.Text())
		if input == "" {
			continue
		}

		// 命令处理
		if strings.HasPrefix(input, "/") {
			handleCommand(ctx, runner, &currentSession, input, sessionManager)
			continue
		}

		// 执行查询
		if err := runner.Query(ctx, currentSession, input); err != nil {
			log.Printf("查询失败: %v", err)
		}
	}

	if err := scanner.Err(); err != nil {
		log.Fatalf("读取输入错误: %v", err)
	}
}

func handleCommand(ctx context.Context, runner *agent.Runner, currentSession *string, input string, sm *session.Manager) {
	parts := strings.Fields(input)
	cmd := parts[0]

	switch cmd {
	case "/new":
		if len(parts) < 2 {
			fmt.Println("用法: /new <session_id>")
			return
		}
		*currentSession = parts[1]
		fmt.Printf("已切换到会话: %s\n", *currentSession)

	case "/history":
		msgs, err := runner.GetSessionHistory(ctx, *currentSession)
		if err != nil {
			fmt.Printf("获取历史失败: %v\n", err)
			return
		}
		fmt.Printf("\n会话历史 (共 %d 条消息):\n", len(msgs))
		for i, msg := range msgs {
			role := string(msg.Role)
			content := msg.Content
			if len(content) > 60 {
				content = content[:60] + "..."
			}
			fmt.Printf("  [%d] %s: %s\n", i+1, role, content)
		}

	case "/list":
		sessions := runner.ListSessions()
		fmt.Printf("\n活跃会话 (共 %d 个):\n", len(sessions))
		for _, s := range sessions {
			marker := ""
			if s == *currentSession {
				marker = " *"
			}
			fmt.Printf("  - %s%s\n", s, marker)
		}

	case "/clear":
		if err := runner.ClearSession(ctx, *currentSession); err != nil {
			fmt.Printf("清除会话失败: %v\n", err)
			return
		}
		fmt.Printf("会话 %s 已清除\n", *currentSession)

	case "/quit", "/exit":
		fmt.Println("\n再见！")
		os.Exit(0)

	default:
		fmt.Println("未知命令。可用命令: /new, /history, /list, /clear, /quit")
	}
}
