package config

import (
	"os"
	"strings"

	"gopkg.in/yaml.v3"
)

type Config struct {
	Agent      AgentConfig      `yaml:"agent"`
	Model      ModelConfig      `yaml:"model"`
	Session    SessionConfig    `yaml:"session"`
	Middleware MiddlewareConfig `yaml:"middleware"`
	Server     ServerConfig     `yaml:"server"`
}

type AgentConfig struct {
	Name          string `yaml:"name"`
	Description   string `yaml:"description"`
	Instruction   string `yaml:"instruction"`
	MaxIterations int    `yaml:"max_iterations"`
}

type ModelConfig struct {
	Provider    string  `yaml:"provider"`
	ModelName   string  `yaml:"model_name"`
	APIKey      string  `yaml:"api_key"`
	Temperature float32 `yaml:"temperature"`
}

type SessionConfig struct {
	MaxHistory int    `yaml:"max_history"` // 最大历史消息数
	StoreType  string `yaml:"store_type"`  // memory, redis, etc.
	RedisURL   string `yaml:"redis_url"`   // Redis 连接地址（如果使用 Redis）
}

type MiddlewareConfig struct {
	Filesystem    FilesystemMiddlewareConfig    `yaml:"filesystem"`
	Summarization SummarizationMiddlewareConfig `yaml:"summarization"`
	Reduction     ReductionMiddlewareConfig     `yaml:"reduction"`
}

type FilesystemMiddlewareConfig struct {
	Enabled bool   `yaml:"enabled"`
	BaseDir string `yaml:"base_dir"`
}

type SummarizationMiddlewareConfig struct {
	Enabled       bool `yaml:"enabled"`
	ContextTokens int  `yaml:"context_tokens"`
}

type ReductionMiddlewareConfig struct {
	Enabled    bool `yaml:"enabled"`
	MaxTokens  int  `yaml:"max_tokens"`
}

type ServerConfig struct {
	EnableStreaming bool   `yaml:"enable_streaming"`
	LogLevel        string `yaml:"log_level"`
}

func Load(path string) (*Config, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		return nil, err
	}

	content := os.ExpandEnv(string(data))

	var cfg Config
	if err := yaml.Unmarshal([]byte(content), &cfg); err != nil {
		return nil, err
	}

	if strings.HasPrefix(cfg.Model.APIKey, "${") && strings.HasSuffix(cfg.Model.APIKey, "}") {
		envVar := cfg.Model.APIKey[2 : len(cfg.Model.APIKey)-1]
		cfg.Model.APIKey = os.Getenv(envVar)
	}

	return &cfg, nil
}
