```go
package agent

import (
	"context"
	"errors"
	"fmt"
	"io"
	"log"
	"strings"

	"github.com/cloudwego/eino/adk"
	"github.com/cloudwego/eino/schema"

	"my-eino-agent/internal/config"
	"my-eino-agent/internal/session"
)

// ========================================
// 类型定义
// ========================================

// RunnerEvent 表示处理后的 Runner 事件，用于通知外部
type RunnerEvent struct {
	Type RunnerEventType
	Data any
}

type RunnerEventType string

const (
	EventTypeUserMessage     RunnerEventType = "user_message"      // 用户消息
	EventTypeAssistantText   RunnerEventType = "assistant_text"    // Assistant 文本输出
	EventTypeToolCallRequest RunnerEventType = "tool_call_request" // 工具调用请求（模型发起）
	EventTypeToolCallResult  RunnerEventType = "tool_call_result"  // 工具调用结果
	EventTypeError           RunnerEventType = "error"             // 错误
	EventTypeDone            RunnerEventType = "done"              // 完成一轮对话
)

// ToolCallRequestData 工具调用请求数据
type ToolCallRequestData struct {
	Name      string
	Arguments string
}

// ToolCallResultData 工具调用结果数据
type ToolCallResultData struct {
	ToolName string
	Content  string
	Truncated bool
}

// AssistantTextData Assistant 文本数据
type AssistantTextData struct {
	Content   string
	Streaming bool
}

// ========================================
// Runner 结构
// ========================================

// Runner 封装的 Agent Runner（支持会话存储）
type Runner struct {
	runner   *adk.Runner
	cfg      *config.Config
	sessions *session.Manager
}

// NewRunner 创建 Runner
func NewRunner(cfg *config.Config, agent adk.Agent, sessionManager *session.Manager) *Runner {
	return &Runner{
		runner: adk.NewRunner(context.Background(), adk.RunnerConfig{
			Agent:           agent,
			EnableStreaming: cfg.Server.EnableStreaming,
		}),
		cfg:      cfg,
		sessions: sessionManager,
	}
}

// ========================================
// 核心方法
// ========================================

// Query 执行查询并处理输出
// 返回最终 Assistant 的文本内容（用于保存历史）
func (r *Runner) Query(ctx context.Context, sessionID, query string) (string, error) {
	// 1. 打印用户输入
	fmt.Printf("\n[Session: %s]\n", sessionID)
	fmt.Printf("用户: %s\n", query)

	// 2. 获取会话并添加用户消息
	sess, err := r.sessions.GetOrCreate(ctx, sessionID)
	if err != nil {
		return "", fmt.Errorf("failed to get session: %w", err)
	}

	userMsg := schema.UserMessage(query)
	if err := r.sessions.AddMessage(ctx, sessionID, userMsg); err != nil {
		log.Printf("Warning: failed to add user message: %v", err)
	}

	// 3. 执行 Agent
	history := sess.Messages
	allMsgs := append(history, userMsg)
	iter := r.runner.Run(ctx, allMsgs)

	// 4. 处理事件流，收集最终文本
	finalContent, err := r.processEventStream(ctx, sessionID, iter)
	if err != nil {
		return "", err
	}

	// 5. 保存 Assistant 消息到会话（只保存最终文本，不含工具调用）
	if finalContent != "" {
		assistantMsg := schema.AssistantMessage(finalContent, nil)
		if err := r.sessions.AddMessage(ctx, sessionID, assistantMsg); err != nil {
			log.Printf("Warning: failed to add assistant message: %v", err)
		}
	}

	// 6. 持久化会话
	if err := r.sessions.Save(ctx, sessionID); err != nil {
		log.Printf("Warning: failed to save session: %v", err)
	}

	fmt.Println() // 换行分隔
	return finalContent, nil
}

// processEventStream 处理事件流，区分输出和存储
func (r *Runner) processEventStream(ctx context.Context, sessionID string, iter *adk.AsyncIterator[*adk.AgentEvent]) (string, error) {
	var contentBuilder strings.Builder

	for {
		event, ok := iter.Next()
		if !ok {
			break
		}

		// 1. 处理错误
		if event.Err != nil {
			r.printError(event.Err)
			return contentBuilder.String(), event.Err
		}

		// 2. 处理 Action（如中断、转移等）
		if event.Action != nil {
			r.handleAction(event.Action)
			continue
		}

		// 3. 处理消息输出
		if event.Output != nil && event.Output.MessageOutput != nil {
			mv := event.Output.MessageOutput
			content := r.handleMessageOutput(mv, &contentBuilder)
			// handleMesssageOutput 返回的是本轮次中 Assistant 的文本内容
			// 累积到 contentBuilder 中
			if content != "" {
				contentBuilder.WriteString(content)
			}
		}
	}

	return contentBuilder.String(), nil
}

// ========================================
// 消息处理（核心逻辑）
// ========================================

// handleMessageOutput 处理消息输出
// 返回 Assistant 的文本内容（用于保存历史）
func (r *Runner) handleMessageOutput(mv *adk.MessageVariant, contentBuilder *strings.Builder) string {
	// ==================== Tool 消息（工具执行结果）====================
	// 工具结果：只打印，不保存到会话历史
	if mv.Role == schema.Tool {
		result := r.drainToolResult(mv)
		r.printToolResult(mv.ToolName, result)
		return "" // 不保存
	}

	// ==================== Assistant 消息 ====================
	if mv.Role == schema.Assistant {
		if mv.IsStreaming {
			return r.handleStreamingAssistant(mv, contentBuilder)
		}
		return r.handleNonStreamingAssistant(mv, contentBuilder)
	}

	// 其他角色消息不处理
	return ""
}

// handleStreamingAssistant 处理流式 Assistant 消息
// 返回文本内容
func (r *Runner) handleStreamingAssistant(mv *adk.MessageVariant, contentBuilder *strings.Builder) string {
	mv.MessageStream.SetAutomaticClose()

	var textContent strings.Builder
	var toolCalls []schema.ToolCall

	fmt.Print("助手: ") // 打印前缀

	for {
		chunk, err := mv.MessageStream.Recv()
		if errors.Is(err, io.EOF) {
			break
		}
		if err != nil {
			r.printError(err)
			return textContent.String()
		}

		if chunk == nil {
			continue
		}

		// 1. 处理文本内容：实时打印 + 累积
		if chunk.Content != "" {
			fmt.Print(chunk.Content)
			textContent.WriteString(chunk.Content)
		}

		// 2. 累积 ToolCalls（模型请求调用工具）
		if len(chunk.ToolCalls) > 0 {
			toolCalls = append(toolCalls, chunk.ToolCalls...)
		}
	}

	fmt.Println() // 流结束换行

	// 3. 打印工具调用请求（如果有）
	if len(toolCalls) > 0 {
		mergedToolCalls := r.mergeToolCalls(toolCalls)
		for _, tc := range mergedToolCalls {
			r.printToolCallRequest(tc.Function.Name, tc.Function.Arguments)
		}
	}

	// 返回文本内容（不含工具调用，用于保存历史）
	return textContent.String()
}

// handleNonStreamingAssistant 处理非流式 Assistant 消息
// 返回文本内容
func (r *Runner) handleNonStreamingAssistant(mv *adk.MessageVariant, contentBuilder *strings.Builder) string {
	if mv.Message == nil {
		return ""
	}

	msg := mv.Message

	// 1. 打印文本内容
	if msg.Content != "" {
		fmt.Printf("助手: %s\n", msg.Content)
	}

	// 2. 打印工具调用请求（如果有）
	for _, tc := range msg.ToolCalls {
		r.printToolCallRequest(tc.Function.Name, tc.Function.Arguments)
	}

	// 返回文本内容（不含工具调用）
	return msg.Content
}

// ========================================
// 工具调用处理
// ========================================

// drainToolResult 消费工具结果（流式或非流式）
func (r *Runner) drainToolResult(mv *adk.MessageVariant) string {
	if mv.IsStreaming && mv.MessageStream != nil {
		var sb strings.Builder
		for {
			chunk, err := mv.MessageStream.Recv()
			if errors.Is(err, io.EOF) {
				break
			}
			if err != nil {
				break
			}
			if chunk != nil && chunk.Content != "" {
				sb.WriteString(chunk.Content)
			}
		}
		return sb.String()
	}

	if mv.Message != nil {
		return mv.Message.Content
	}
	return ""
}

// mergeToolCalls 合并流式输出的 ToolCalls chunks
func (r *Runner) mergeToolCalls(chunks []schema.ToolCall) []schema.ToolCall {
	// 按 Index 分组
	groups := make(map[int][]schema.ToolCall)
	for _, tc := range chunks {
		if tc.Index != nil {
			groups[*tc.Index] = append(groups[*tc.Index], tc)
		}
	}

	// 合并每组
	result := make([]schema.ToolCall, 0, len(groups))
	for _, group := range groups {
		if len(group) == 0 {
			continue
		}

		merged := schema.ToolCall{
			ID:   group[0].ID,
			Type: group[0].Type,
			Index: group[0].Index,
		}

		// 合并 Arguments（流式输出时 Arguments 是逐步累积的）
		var argsBuilder strings.Builder
		var nameBuilder strings.Builder
		for _, tc := range group {
			if tc.Function.Name != "" {
				nameBuilder.WriteString(tc.Function.Name)
			}
			if tc.Function.Arguments != "" {
				argsBuilder.WriteString(tc.Function.Arguments)
			}
		}
		merged.Function.Name = nameBuilder.String()
		merged.Function.Arguments = argsBuilder.String()

		// 只保留完整的 ToolCall
		if merged.Function.Name != "" {
			result = append(result, merged)
		}
	}

	return result
}

// ========================================
// 输出格式化（打印）
// ========================================

// printToolCallRequest 打印工具调用请求
func (r *Runner) printToolCallRequest(name, arguments string) {
	fmt.Printf("  🔧 [调用工具] %s(%s)\n", name, r.truncate(arguments, 100))
}

// printToolResult 打印工具执行结果
func (r *Runner) printToolResult(toolName, result string) {
	truncated := len(result) > 200
	display := r.truncate(result, 200)
	if truncated {
		display += "..."
	}
	fmt.Printf("  ✅ [工具结果] %s: %s\n", toolName, display)
}

// printError 打印错误
func (r *Runner) printError(err error) {
	fmt.Printf("  ❌ [错误] %v\n", err)
}

// handleAction 处理 Action 事件
func (r *Runner) handleAction(action *adk.AgentAction) {
	if action.Interrupted != nil {
		fmt.Printf("  ⏸️ [中断] 等待用户输入...\n")
	}
	if action.TransferToAgent != nil {
		fmt.Printf("  ➡️ [转移] 切换到 Agent: %s\n", action.TransferToAgent.DestAgentName)
	}
	if action.Exit {
		fmt.Printf("  🏁 [退出] Agent 执行结束\n")
	}
}

// truncate 截断字符串
func (r *Runner) truncate(s string, maxLen int) string {
	if len(s) <= maxLen {
		return s
	}
	return s[:maxLen]
}

// ========================================
// 会话管理方法
// ========================================

// GetSessionHistory 获取会话历史
func (r *Runner) GetSessionHistory(ctx context.Context, sessionID string) ([]*schema.Message, error) {
	return r.sessions.GetMessages(ctx, sessionID)
}

// ClearSession 清除会话
func (r *Runner) ClearSession(ctx context.Context, sessionID string) error {
	return r.sessions.Clear(ctx, sessionID)
}

// ListSessions 列出所有会话
func (r *Runner) ListSessions() []string {
	return r.sessions.List()
}

// GetSessionManager 获取会话管理器
func (r *Runner) GetSessionManager() *session.Manager {
	return r.sessions
}
