```go
package agent

import (
	"context"
	"errors"
	"fmt"
	"io"
	"log"
	"strings"
	"sync"

	"github.com/cloudwego/eino/adk"
	"github.com/cloudwego/eino/components/tool"
	"github.com/cloudwego/eino/schema"

	"my-eino-agent/internal/config"
	"my-eino-agent/internal/session"
)

// ========================================
// 类型定义
// ========================================

// RunnerState Runner 状态
type RunnerState string

const (
	StateIdle       RunnerState = "idle"        // 空闲
	StateRunning    RunnerState = "running"     // 执行中
	StateInterrupted RunnerState = "interrupted" // 已中断，等待用户输入
	StateExited     RunnerState = "exited"      // 已退出
)

// InterruptContext 中断上下文
type InterruptContext struct {
	CheckPointID string         // Checkpoint ID（用于恢复）
	InterruptID  string         // 中断 ID（用于指定恢复目标）
	Info         any            // 中断信息（展示给用户）
	SessionID    string         // 会话 ID
	Prompt       string        // 用户提示（如果有）
}

// Runner 封装的 Agent Runner
type Runner struct {
	runner   *adk.Runner
	cfg      *config.Config
	sessions *session.Manager

	// 状态管理
	mu              sync.RWMutex
	state           RunnerState
	currentContext  *InterruptContext // 当前中断上下文（如果有）
}

// NewRunner 创建 Runner
func NewRunner(cfg *config.Config, agent adk.Agent, sessionManager *session.Manager) *Runner {
	return &Runner{
		runner: adk.NewRunner(context.Background(), adk.RunnerConfig{
			Agent:           agent,
			EnableStreaming: cfg.Server.EnableStreaming,
		}),
		cfg:      cfg,
		sessions: sessionManager,
		state:    StateIdle,
	}
}

// ========================================
// 公共 API
// ========================================

// Query 执行查询
func (r *Runner) Query(ctx context.Context, sessionID, query string) (string, error) {
	// 1. 检查是否在中断状态
	if r.IsInterrupted() {
		return "", fmt.Errorf("runner is interrupted, please use Resume() to continue or Cancel() to cancel")
	}

	// 2. 设置状态
	r.setState(StateRunning)

	// 3. 打印用户输入
	fmt.Printf("\n[Session: %s]\n", sessionID)
	fmt.Printf("👤 用户: %s\n", query)

	// 4. 获取会话并添加用户消息
	sess, err := r.sessions.GetOrCreate(ctx, sessionID)
	if err != nil {
		r.setState(StateIdle)
		return "", fmt.Errorf("failed to get session: %w", err)
	}

	userMsg := schema.UserMessage(query)
	if err := r.sessions.AddMessage(ctx, sessionID, userMsg); err != nil {
		log.Printf("Warning: failed to add user message: %v", err)
	}

	// 5. 执行 Agent
	history := sess.Messages
	allMsgs := append(history, userMsg)

	// 使用 checkpoint ID 支持中断恢复
	checkPointID := fmt.Sprintf("cp-%s", sessionID)
	iter := r.runner.Run(ctx, allMsgs, adk.WithCheckPointID(checkPointID))

	// 6. 处理事件流
	finalContent, err := r.processEventStream(ctx, sessionID, iter, checkPointID)
	if err != nil {
		r.setState(StateIdle)
		return "", err
	}

	// 7. 检查是否在中断状态
	if r.IsInterrupted() {
		// 中断状态不保存消息，等待恢复
		return finalContent, nil
	}

	// 8. 保存 Assistant 消息
	if finalContent != "" {
		assistantMsg := schema.AssistantMessage(finalContent, nil)
		if err := r.sessions.AddMessage(ctx, sessionID, assistantMsg); err != nil {
			log.Printf("Warning: failed to add assistant message: %v", err)
		}
	}

	// 9. 持久化会话
	if err := r.sessions.Save(ctx, sessionID); err != nil {
		log.Printf("Warning: failed to save session: %v", err)
	}

	r.setState(StateIdle)
	fmt.Println() // 换行分隔
	return finalContent, nil
}

// Resume 恢复中断的执行
func (r *Runner) Resume(ctx context.Context, userInput string) (string, error) {
	// 1. 检查是否在中断状态
	if !r.IsInterrupted() {
		return "", fmt.Errorf("runner is not in interrupted state")
	}

	r.mu.RLock()
	ictx := r.currentContext
	r.mu.RUnlock()

	if ictx == nil {
		return "", fmt.Errorf("no interrupt context found")
	}

	// 2. 打印用户输入
	fmt.Printf("\n👤 用户输入: %s\n", userInput)

	// 3. 构建恢复参数
	params := &adk.ResumeParams{
		Targets: map[string]any{
			ictx.InterruptID: userInput,
		},
	}

	// 4. 恢复执行
	r.setState(StateRunning)
	iter, err := r.runner.ResumeWithParams(ctx, ictx.CheckPointID, params)
	if err != nil {
		r.setState(StateInterrupted)
		return "", fmt.Errorf("failed to resume: %w", err)
	}

	// 5. 清空中断上下文
	r.clearInterruptContext()

	// 6. 处理事件流
	finalContent, err := r.processEventStream(ctx, ictx.SessionID, iter, ictx.CheckPointID)
	if err != nil {
		r.setState(StateIdle)
		return "", err
	}

	// 7. 再次检查是否中断
	if r.IsInterrupted() {
		return finalContent, nil
	}

	// 8. 保存消息
	if finalContent != "" {
		assistantMsg := schema.AssistantMessage(finalContent, nil)
		if err := r.sessions.AddMessage(ctx, ictx.SessionID, assistantMsg); err != nil {
			log.Printf("Warning: failed to add assistant message: %v", err)
		}
	}

	if err := r.sessions.Save(ctx, ictx.SessionID); err != nil {
		log.Printf("Warning: failed to save session: %v", err)
	}

	r.setState(StateIdle)
	fmt.Println()
	return finalContent, nil
}

// ResumeWithApproval 恢复执行并批准工具调用
func (r *Runner) ResumeWithApproval(ctx context.Context, approved bool, modifiedInput any) (string, error) {
	if !r.IsInterrupted() {
		return "", fmt.Errorf("runner is not in interrupted state")
	}

	r.mu.RLock()
	ictx := r.currentContext
	r.mu.RUnlock()

	if ictx == nil {
		return "", fmt.Errorf("no interrupt context found")
	}

	// 构建批准结果
	approvalResult := &tool.ApprovalResult{
		Approved: approved,
	}
	if modifiedInput != nil {
		approvalResult.ModifiedInput = modifiedInput
	}

	// 打印决定
	if approved {
		fmt.Printf("\n✅ 用户批准执行\n")
	} else {
		fmt.Printf("\n❌ 用户拒绝执行\n")
	}

	// 恢复执行
	params := &adk.ResumeParams{
		Targets: map[string]any{
			ictx.InterruptID: approvalResult,
		},
	}

	r.setState(StateRunning)
	iter, err := r.runner.ResumeWithParams(ctx, ictx.CheckPointID, params)
	if err != nil {
		r.setState(StateInterrupted)
		return "", fmt.Errorf("failed to resume: %w", err)
	}

	r.clearInterruptContext()
	finalContent, err := r.processEventStream(ctx, ictx.SessionID, iter, ictx.CheckPointID)
	if err != nil {
		r.setState(StateIdle)
		return "", err
	}

	if !r.IsInterrupted() && finalContent != "" {
		assistantMsg := schema.AssistantMessage(finalContent, nil)
		r.sessions.AddMessage(ctx, ictx.SessionID, assistantMsg)
		r.sessions.Save(ctx, ictx.SessionID)
	}

	r.setState(StateIdle)
	fmt.Println()
	return finalContent, nil
}

// Cancel 取消中断状态
func (r *Runner) Cancel() {
	r.clearInterruptContext()
	r.setState(StateIdle)
	fmt.Println("\n⚠️ 已取消当前操作")
}

// ========================================
// 状态管理
// ========================================

// GetState 获取当前状态
func (r *Runner) GetState() RunnerState {
	r.mu.RLock()
	defer r.mu.RUnlock()
	return r.state
}

// IsInterrupted 检查是否在中断状态
func (r *Runner) IsInterrupted() bool {
	r.mu.RLock()
	defer r.mu.RUnlock()
	return r.state == StateInterrupted
}

// GetInterruptContext 获取中断上下文
func (r *Runner) GetInterruptContext() *InterruptContext {
	r.mu.RLock()
	defer r.mu.RUnlock()
	return r.currentContext
}

func (r *Runner) setState(state RunnerState) {
	r.mu.Lock()
	r.state = state
	r.mu.Unlock()
}

func (r *Runner) setInterruptContext(ictx *InterruptContext) {
	r.mu.Lock()
	r.currentContext = ictx
	r.state = StateInterrupted
	r.mu.Unlock()
}

func (r *Runner) clearInterruptContext() {
	r.mu.Lock()
	r.currentContext = nil
	r.mu.Unlock()
}

// ========================================
// 事件处理
// ========================================

// processEventStream 处理事件流
func (r *Runner) processEventStream(ctx context.Context, sessionID string, iter *adk.AsyncIterator[*adk.AgentEvent], checkPointID string) (string, error) {
	var contentBuilder strings.Builder

	for {
		event, ok := iter.Next()
		if !ok {
			break
		}

		// 1. 处理错误
		if event.Err != nil {
			r.printError(event.Err)
			return contentBuilder.String(), event.Err
		}

		// 2. 处理 Action（核心）
		if event.Action != nil {
			shouldReturn, err := r.handleAction(ctx, sessionID, checkPointID, event.Action, &contentBuilder)
			if shouldReturn {
				return contentBuilder.String(), err
			}
			continue
		}

		// 3. 处理消息输出
		if event.Output != nil && event.Output.MessageOutput != nil {
			mv := event.Output.MessageOutput
			content := r.handleMessageOutput(mv)
			if content != "" {
				contentBuilder.WriteString(content)
			}
		}
	}

	return contentBuilder.String(), nil
}

// handleAction 处理 Action 事件
// 返回 true 表示应该停止处理事件流
func (r *Runner) handleAction(ctx context.Context, sessionID, checkPointID string, action *adk.AgentAction, contentBuilder *strings.Builder) (shouldReturn bool, err error) {
	// ==================== 1. 中断处理 ====================
	if action.Interrupted != nil {
		return r.handleInterrupt(sessionID, checkPointID, action.Interrupted)
	}

	// ==================== 2. Agent 转移 ====================
	if action.TransferToAgent != nil {
		r.handleTransfer(action.TransferToAgent)
		return false, nil // 转移后继续执行
	}

	// ==================== 3. 退出 ====================
	if action.Exit {
		r.handleExit()
		r.setState(StateExited)
		return true, nil
	}

	// ==================== 4. BreakLoop ====================
	if action.BreakLoop != nil {
		fmt.Printf("  🔄 [BreakLoop] 跳出循环\n")
		return false, nil
	}

	// ==================== 5. 自定义 Action ====================
	if action.CustomizedAction != nil {
		fmt.Printf("  ⚙️ [CustomAction] %v\n", action.CustomizedAction)
		return false, nil
	}

	return false, nil
}

// handleInterrupt 处理中断
func (r *Runner) handleInterrupt(sessionID, checkPointID string, info *adk.InterruptInfo) (bool, error) {
	// 1. 获取中断上下文
	if len(info.InterruptContexts) == 0 {
		return false, fmt.Errorf("interrupt info has no contexts")
	}

	ic := info.InterruptContexts[0] // 取第一个中断点
	interruptID := ic.ID
	interruptInfo := ic.Info

	// 2. 解析中断信息，判断类型
	var prompt string
	var interruptType string

	switch v := interruptInfo.(type) {
	case string:
		prompt = v
		interruptType = "clarification"
	case *ApprovalRequest:
		interruptType = "approval"
		prompt = v.Message
	case map[string]any:
		if msg, ok := v["message"].(string); ok {
			prompt = msg
		}
		if t, ok := v["type"].(string); ok {
			interruptType = t
		}
	default:
		prompt = fmt.Sprintf("%v", interruptInfo)
		interruptType = "unknown"
	}

	// 3. 打印中断信息
	fmt.Println()
	fmt.Println("  ⏸️  ─────────────────────────────────")
	fmt.Println("  ⏸️  [中断] Agent 请求用户输入")
	fmt.Printf("  ⏸️  类型: %s\n", interruptType)
	fmt.Printf("  ⏸️  信息: %s\n", prompt)
	fmt.Println("  ⏸️  ─────────────────────────────────")

	// 4. 保存中断上下文
	r.setInterruptContext(&InterruptContext{
		CheckPointID: checkPointID,
		InterruptID:  interruptID,
		Info:         interruptInfo,
		SessionID:    sessionID,
		Prompt:       prompt,
	})

	// 5. 根据类型显示不同的提示
	switch interruptType {
	case "approval":
		fmt.Println("\n  请选择操作:")
		fmt.Println("    /approve   - 批准执行")
		fmt.Println("    /reject    - 拒绝执行")
		fmt.Println("    /cancel    - 取消操作")
	default:
		fmt.Println("\n  请输入回复，或输入 /cancel 取消操作")
	}

	// 6. 返回 true 表示需要等待用户输入
	return true, nil
}

// handleTransfer 处理 Agent 转移
func (r *Runner) handleTransfer(action *adk.TransferToAgentAction) {
	fmt.Printf("  ➡️ [Transfer] 切换到 Agent: %s\n", action.DestAgentName)
	if action.Message != "" {
		fmt.Printf("  ➡️ 消息: %s\n", action.Message)
	}
}

// handleExit 处理退出
func (r *Runner) handleExit() {
	fmt.Println("  🏁 [Exit] Agent 执行结束")
}

// ========================================
// 消息处理
// ========================================

// handleMessageOutput 处理消息输出
func (r *Runner) handleMessageOutput(mv *adk.MessageVariant) string {
	// Tool 消息：只打印，不保存
	if mv.Role == schema.Tool {
		result := r.drainToolResult(mv)
		r.printToolResult(mv.ToolName, result)
		return ""
	}

	// Assistant 消息
	if mv.Role == schema.Assistant {
		if mv.IsStreaming {
			return r.handleStreamingAssistant(mv)
		}
		return r.handleNonStreamingAssistant(mv)
	}

	return ""
}

// handleStreamingAssistant 处理流式 Assistant 消息
func (r *Runner) handleStreamingAssistant(mv *adk.MessageVariant) string {
	mv.MessageStream.SetAutomaticClose()

	var textContent strings.Builder
	var toolCalls []schema.ToolCall

	fmt.Print("🤖 助手: ")

	for {
		chunk, err := mv.MessageStream.Recv()
		if errors.Is(err, io.EOF) {
			break
		}
		if err != nil {
			r.printError(err)
			return textContent.String()
		}

		if chunk == nil {
			continue
		}

		// 处理文本
		if chunk.Content != "" {
			fmt.Print(chunk.Content)
			textContent.WriteString(chunk.Content)
		}

		// 累积 ToolCalls
		if len(chunk.ToolCalls) > 0 {
			toolCalls = append(toolCalls, chunk.ToolCalls...)
		}
	}

	fmt.Println()

	// 打印工具调用请求
	if len(toolCalls) > 0 {
		merged := r.mergeToolCalls(toolCalls)
		for _, tc := range merged {
			r.printToolCallRequest(tc.Function.Name, tc.Function.Arguments)
		}
	}

	return textContent.String()
}

// handleNonStreamingAssistant 处理非流式 Assistant 消息
func (r *Runner) handleNonStreamingAssistant(mv *adk.MessageVariant) string {
	if mv.Message == nil {
		return ""
	}

	msg := mv.Message

	if msg.Content != "" {
		fmt.Printf("🤖 助手: %s\n", msg.Content)
	}

	// 打印工具调用请求
	for _, tc := range msg.ToolCalls {
		r.printToolCallRequest(tc.Function.Name, tc.Function.Arguments)
	}

	return msg.Content
}

// ========================================
// 工具调用处理
// ========================================

// drainToolResult 消费工具结果
func (r *Runner) drainToolResult(mv *adk.MessageVariant) string {
	if mv.IsStreaming && mv.MessageStream != nil {
		var sb strings.Builder
		for {
			chunk, err := mv.MessageStream.Recv()
			if errors.Is(err, io.EOF) {
				break
			}
			if err != nil {
				break
			}
			if chunk != nil && chunk.Content != "" {
				sb.WriteString(chunk.Content)
			}
		}
		return sb.String()
	}

	if mv.Message != nil {
		return mv.Message.Content
	}
	return ""
}

// mergeToolCalls 合并流式 ToolCalls
func (r *Runner) mergeToolCalls(chunks []schema.ToolCall) []schema.ToolCall {
	groups := make(map[int][]schema.ToolCall)
	for _, tc := range chunks {
		if tc.Index != nil {
			groups[*tc.Index] = append(groups[*tc.Index], tc)
		}
	}

	result := make([]schema.ToolCall, 0, len(groups))
	for _, group := range groups {
		if len(group) == 0 {
			continue
		}

		merged := schema.ToolCall{
			ID:    group[0].ID,
			Type:  group[0].Type,
			Index: group[0].Index,
		}

		var argsBuilder, nameBuilder strings.Builder
		for _, tc := range group {
			if tc.Function.Name != "" {
				nameBuilder.WriteString(tc.Function.Name)
			}
			if tc.Function.Arguments != "" {
				argsBuilder.WriteString(tc.Function.Arguments)
			}
		}
		merged.Function.Name = nameBuilder.String()
		merged.Function.Arguments = argsBuilder.String()

		if merged.Function.Name != "" {
			result = append(result, merged)
		}
	}

	return result
}

