```go
package main

import (
	"bufio"
	"context"
	"fmt"
	"log"
	"os"
	"strings"

	"my-eino-agent/internal/agent"
	"my-eino-agent/internal/config"
	"my-eino-agent/internal/session"
)

func main() {
	ctx := context.Background()

	// 1. 加载配置
	cfg, err := config.Load("./config/config.yaml")
	if err != nil {
		log.Fatalf("加载配置失败: %v", err)
	}

	fmt.Println("========================================")
	fmt.Printf("  %s 启动中...\n", cfg.Agent.Name)
	fmt.Println("========================================")

	// 2. 构建会话管理器
	sessionManager := session.NewManager(&session.ManagerConfig{
		Store:      session.NewInMemoryStore(),
		MaxHistory: cfg.Session.MaxHistory,
	})

	// 3. 构建 Agent
	builder := agent.NewBuilder(cfg)

	if err := builder.InitModel(ctx); err != nil {
		log.Fatalf("初始化模型失败: %v", err)
	}

	if err := builder.InitTools(); err != nil {
		log.Fatalf("初始化工具失败: %v", err)
	}

	ag, err := builder.Build(ctx)
	if err != nil {
		log.Fatalf("构建 Agent 失败: %v", err)
	}

	// 4. 创建 Runner
	runner := agent.NewRunner(cfg, ag, sessionManager)

	printHelp()
	currentSession := "default"

	// 5. 交互式对话
	scanner := bufio.NewScanner(os.Stdin)
	for {
		// 显示当前状态
		state := runner.GetState()
		if state == agent.StateInterrupted {
			ictx := runner.GetInterruptContext()
			fmt.Printf("\n⏸️  [等待输入] %s\n", ictx.Prompt)
			fmt.Printf("[%s][中断] > ", currentSession)
		} else {
			fmt.Printf("\n[%s] > ", currentSession)
		}

		if !scanner.Scan() {
			break
		}

		input := strings.TrimSpace(scanner.Text())
		if input == "" {
			continue
		}

		// 命令处理
		if strings.HasPrefix(input, "/") {
			shouldExit := handleCommand(ctx, runner, &currentSession, input)
			if shouldExit {
				break
			}
			continue
		}

		// 根据状态处理输入
		switch runner.GetState() {
		case agent.StateInterrupted:
			// 在中断状态，用户输入作为恢复数据
			if _, err := runner.Resume(ctx, input); err != nil {
				log.Printf("恢复失败: %v", err)
			}
		default:
			// 正常查询
			if _, err := runner.Query(ctx, currentSession, input); err != nil {
				log.Printf("查询失败: %v", err)
			}
		}
	}

	if err := scanner.Err(); err != nil {
		log.Fatalf("读取输入错误: %v", err)
	}
}

func printHelp() {
	fmt.Println("\n助手已就绪！")
	fmt.Println("命令:")
	fmt.Println("  /new <session_id>  - 创建/切换会话")
	fmt.Println("  /history           - 查看当前会话历史")
	fmt.Println("  /list              - 列出所有会话")
	fmt.Println("  /clear             - 清除当前会话")
	fmt.Println("  /status            - 查看 Runner 状态")
	fmt.Println("  /approve           - 批准当前操作（中断时）")
	fmt.Println("  /reject            - 拒绝当前操作（中断时）")
	fmt.Println("  /cancel            - 取消当前中断")
	fmt.Println("  /quit              - 退出程序")
	fmt.Println("----------------------------------------")
}

func handleCommand(ctx context.Context, runner *agent.Runner, currentSession *string, input string) bool {
	parts := strings.Fields(input)
	cmd := parts[0]

	switch cmd {
	case "/new":
		if len(parts) < 2 {
			fmt.Println("用法: /new <session_id>")
			return false
		}
		*currentSession = parts[1]
		fmt.Printf("已切换到会话: %s\n", *currentSession)

	case "/history":
		msgs, err := runner.GetSessionHistory(ctx, *currentSession)
		if err != nil {
			fmt.Printf("获取历史失败: %v\n", err)
			return false
		}
		printSessionHistory(msgs)

	case "/list":
		sessions := runner.ListSessions()
		fmt.Printf("\n活跃会话 (共 %d 个):\n", len(sessions))
		for _, s := range sessions {
			marker := ""
			if s == *currentSession {
				marker = " *"
			}
			fmt.Printf("  - %s%s\n", s, marker)
		}

	case "/clear":
		if err := runner.ClearSession(ctx, *currentSession); err != nil {
			fmt.Printf("清除会话失败: %v\n", err)
			return false
		}
		fmt.Printf("会话 %s 已清除\n", *currentSession)

	case "/status":
		state := runner.GetState()
		fmt.Printf("\n当前状态: %s\n", state)
		if runner.IsInterrupted() {
			ictx := runner.GetInterruptContext()
			fmt.Printf("中断信息:\n")
			fmt.Printf("  CheckPointID: %s\n", ictx.CheckPointID)
			fmt.Printf("  InterruptID: %s\n", ictx.InterruptID)
			fmt.Printf("  SessionID: %s\n", ictx.SessionID)
			fmt.Printf("  提示: %s\n", ictx.Prompt)
		}

	case "/approve":
		if !runner.IsInterrupted() {
			fmt.Println("当前没有待批准的操作")
			return false
		}
		if _, err := runner.ResumeWithApproval(ctx, true, nil); err != nil {
			fmt.Printf("批准失败: %v\n", err)
		}

	case "/reject":
		if !runner.IsInterrupted() {
			fmt.Println("当前没有待拒绝的操作")
			return false
		}
		if _, err := runner.ResumeWithApproval(ctx, false, nil); err != nil {
			fmt.Printf("拒绝失败: %v\n", err)
		}

	case "/cancel":
		if !runner.IsInterrupted() {
			fmt.Println("当前没有中断状态")
			return false
		}
		runner.Cancel()

	case "/quit", "/exit":
		fmt.Println("\n再见！")
		return true

	default:
		fmt.Println("未知命令。可用命令: /new, /history, /list, /clear, /status, /approve, /reject, /cancel, /quit")
	}

	return false
}

func printSessionHistory(msgs []*schema.Message) {
	fmt.Printf("\n会话历史 (共 %d 条消息):\n", len(msgs))
	fmt.Println("----------------------------------------")

	for i, msg := range msgs {
		if msg == nil {
			continue
		}

		content := msg.Content
		if len(content) > 100 {
			content = content[:100] + "..."
		}

		switch msg.Role {
		case schema.User:
			fmt.Printf("  [%d] 👤 用户: %s\n", i+1, content)
		case schema.Assistant:
			if len(msg.ToolCalls) > 0 {
				toolNames := make([]string, len(msg.ToolCalls))
				for j, tc := range msg.ToolCalls {
					toolNames[j] = tc.Function.Name
				}
				fmt.Printf("  [%d] 🤖 助手: [调用工具: %s] %s\n", i+1, strings.Join(toolNames, ", "), content)
			} else {
				fmt.Printf("  [%d] 🤖 助手: %s\n", i+1, content)
			}
		case schema.Tool:
			fmt.Printf("  [%d] 🔧 工具: %s\n", i+1, content)
		case schema.System:
			fmt.Printf("  [%d] ⚙️ 系统: %s\n", i+1, content)
		default:
			fmt.Printf("  [%d] %s: %s\n", i+1, msg.Role, content)
		}
	}
	fmt.Println("----------------------------------------")
}
