package agent

// RunnerState Runner 状态
type RunnerState string

const (
	StateIdle        RunnerState = "idle"        // 空闲
	StateRunning     RunnerState = "running"     // 执行中
	StateInterrupted RunnerState = "interrupted" // 已中断，等待用户输入
	StateExited      RunnerState = "exited"      // 已退出
)

// InterruptContext 中断上下文
type InterruptContext struct {
	CheckPointID string // Checkpoint ID（用于恢复）
	InterruptID  string // 中断 ID（用于指定恢复目标）
	Info         any    // 中断信息（展示给用户）
	SessionID    string // 会话 ID
	Prompt       string // 用户提示（如果有）
	Type         string // 中断类型：clarification/approval 等
}

// ApprovalRequest 批准请求（工具调用前中断）
type ApprovalRequest struct {
	Message      string `json:"message"`
	ToolName     string `json:"tool_name"`
	ToolArgs     any    `json:"tool_args"`
	RequiresEdit bool   `json:"requires_edit"`
}

// EventResult 事件处理结果
type EventResult struct {
	ShouldReturn bool   // 是否应该停止处理事件流
	Content      string // 累积的文本内容
	Err          error  // 错误（如果有）
}
