```go
package agent

import (
	"sync"
)

// StateManager 状态管理器
type StateManager struct {
	mu              sync.RWMutex
	state           RunnerState
	currentContext  *InterruptContext
}

// NewStateManager 创建状态管理器
func NewStateManager() *StateManager {
	return &StateManager{
		state: StateIdle,
	}
}

// GetState 获取当前状态
func (s *StateManager) GetState() RunnerState {
	s.mu.RLock()
	defer s.mu.RUnlock()
	return s.state
}

// SetState 设置状态
func (s *StateManager) SetState(state RunnerState) {
	s.mu.Lock()
	s.state = state
	s.mu.Unlock()
}

// IsInterrupted 检查是否在中断状态
func (s *StateManager) IsInterrupted() bool {
	s.mu.RLock()
	defer s.mu.RUnlock()
	return s.state == StateInterrupted
}

// GetInterruptContext 获取中断上下文
func (s *StateManager) GetInterruptContext() *InterruptContext {
	s.mu.RLock()
	defer s.mu.RUnlock()
	return s.currentContext
}

// SetInterruptContext 设置中断上下文
func (s *StateManager) SetInterruptContext(ictx *InterruptContext) {
	s.mu.Lock()
	s.currentContext = ictx
	s.state = StateInterrupted
	s.mu.Unlock()
}

// ClearInterruptContext 清空中断上下文
func (s *StateManager) ClearInterruptContext() {
	s.mu.Lock()
	s.currentContext = nil
	s.mu.Unlock()
}
