package agent

import (
	"errors"
	"io"
	"strings"

	"github.com/cloudwego/eino/schema"
)

// MessageHandler 消息处理器
type MessageHandler struct {
	output *OutputHandler
}

// NewMessageHandler 创建消息处理器
func NewMessageHandler(output *OutputHandler) *MessageHandler {
	return &MessageHandler{output: output}
}

// MessageResult 消息处理结果
type MessageResult struct {
	Content string // Assistant 的文本内容
}

// HandleMessageOutput 处理消息输出
// 返回 Assistant 的文本内容（用于保存历史）
func (m *MessageHandler) HandleMessageOutput(mv *MessageVariant) *MessageResult {
	// Tool 消息：只打印，不保存
	if mv.Role == schema.Tool {
		result := m.drainToolResult(mv)
		m.output.PrintToolResult(mv.ToolName, result)
		return &MessageResult{Content: ""}
	}

	// Assistant 消息
	if mv.Role == schema.Assistant {
		if mv.IsStreaming {
			return m.handleStreamingAssistant(mv)
		}
		return m.handleNonStreamingAssistant(mv)
	}

	return &MessageResult{Content: ""}
}

// handleStreamingAssistant 处理流式 Assistant 消息
func (m *MessageHandler) handleStreamingAssistant(mv *MessageVariant) *MessageResult {
	mv.MessageStream.SetAutomaticClose()

	var textContent strings.Builder
	var toolCalls []schema.ToolCall

	m.output.PrintAssistantPrefix()

	for {
		chunk, err := mv.MessageStream.Recv()
		if errors.Is(err, io.EOF) {
			break
		}
		if err != nil {
			m.output.PrintError(err)
			return &MessageResult{Content: textContent.String()}
		}

		if chunk == nil {
			continue
		}

		// 处理文本
		if chunk.Content != "" {
			m.output.PrintAssistantText(chunk.Content)
			textContent.WriteString(chunk.Content)
		}

		// 累积 ToolCalls
		if len(chunk.ToolCalls) > 0 {
			toolCalls = append(toolCalls, chunk.ToolCalls...)
		}
	}

	m.output.PrintAssistantNewLine()

	// 打印工具调用请求
	if len(toolCalls) > 0 {
		merged := m.mergeToolCalls(toolCalls)
		for _, tc := range merged {
			m.output.PrintToolCallRequest(tc.Function.Name, tc.Function.Arguments)
		}
	}

	return &MessageResult{Content: textContent.String()}
}

// handleNonStreamingAssistant 处理非流式 Assistant 消息
func (m *MessageHandler) handleNonStreamingAssistant(mv *MessageVariant) *MessageResult {
	if mv.Message == nil {
		return &MessageResult{Content: ""}
	}

	msg := mv.Message

	if msg.Content != "" {
		m.output.PrintAssistantPrefix()
		m.output.PrintAssistantText(msg.Content)
		m.output.PrintAssistantNewLine()
	}

	// 打印工具调用请求
	for _, tc := range msg.ToolCalls {
		m.output.PrintToolCallRequest(tc.Function.Name, tc.Function.Arguments)
	}

	return &MessageResult{Content: msg.Content}
}

// drainToolResult 消费工具结果
func (m *MessageHandler) drainToolResult(mv *MessageVariant) string {
	if mv.IsStreaming && mv.MessageStream != nil {
		var sb strings.Builder
		for {
			chunk, err := mv.MessageStream.Recv()
			if errors.Is(err, io.EOF) {
				break
			}
			if err != nil {
				break
			}
			if chunk != nil && chunk.Content != "" {
				sb.WriteString(chunk.Content)
			}
		}
		return sb.String()
	}

	if mv.Message != nil {
		return mv.Message.Content
	}
	return ""
}

// mergeToolCalls 合并流式 ToolCalls
func (m *MessageHandler) mergeToolCalls(chunks []schema.ToolCall) []schema.ToolCall {
	// 按 Index 分组
	groups := make(map[int][]schema.ToolCall)
	for _, tc := range chunks {
		if tc.Index != nil {
			groups[*tc.Index] = append(groups[*tc.Index], tc)
		}
	}

	// 合并每组
	result := make([]schema.ToolCall, 0, len(groups))
	for _, group := range groups {
		if len(group) == 0 {
			continue
		}

		merged := schema.ToolCall{
			ID:    group[0].ID,
			Type:  group[0].Type,
			Index: group[0].Index,
		}

		var argsBuilder, nameBuilder strings.Builder
		for _, tc := range group {
			if tc.Function.Name != "" {
				nameBuilder.WriteString(tc.Function.Name)
			}
			if tc.Function.Arguments != "" {
				argsBuilder.WriteString(tc.Function.Arguments)
			}
		}
		merged.Function.Name = nameBuilder.String()
		merged.Function.Arguments = argsBuilder.String()

		if merged.Function.Name != "" {
			result = append(result, merged)
		}
	}

	return result
}
