package agent

import (
	"fmt"

	"github.com/cloudwego/eino/adk"
	"github.com/cloudwego/eino/components/tool"
)

// MessageVariant 消息变体（简化 adk.MessageVariant）
type MessageVariant struct {
	Role          schema.Role
	IsStreaming   bool
	Message       *schema.Message
	MessageStream *schema.StreamReader[*schema.Message]
	ToolName      string
}

// EventHandler 事件处理器
type EventHandler struct {
	state  *StateManager
	output *OutputHandler
	msg    *MessageHandler
}

// NewEventHandler 创建事件处理器
func NewEventHandler(state *StateManager, output *OutputHandler) *EventHandler {
	return &EventHandler{
		state:  state,
		output: output,
		msg:    NewMessageHandler(output),
	}
}

// ProcessResult 处理结果
type ProcessResult struct {
	Content      string // 累积的文本内容
	ShouldReturn bool   // 是否应该停止处理
	Err          error  // 错误
}

// ProcessEventStream 处理事件流
func (e *EventHandler) ProcessEventStream(
	sessionID, checkPointID string,
	iter *adk.AsyncIterator[*adk.AgentEvent],
) *ProcessResult {
	var contentBuilder strings.Builder

	for {
		event, ok := iter.Next()
		if !ok {
			break
		}

		// 1. 处理错误
		if event.Err != nil {
			e.output.PrintError(event.Err)
			return &ProcessResult{
				Content:      contentBuilder.String(),
				ShouldReturn: true,
				Err:          event.Err,
			}
		}

		// 2. 处理 Action
		if event.Action != nil {
			result := e.handleAction(sessionID, checkPointID, event.Action, &contentBuilder)
			if result.ShouldReturn {
				return result
			}
			continue
		}

		// 3. 处理消息输出
		if event.Output != nil && event.Output.MessageOutput != nil {
			mv := e.convertMessageVariant(event.Output.MessageOutput)
			msgResult := e.msg.HandleMessageOutput(mv)
			if msgResult.Content != "" {
				contentBuilder.WriteString(msgResult.Content)
			}
		}
	}

	return &ProcessResult{
		Content:      contentBuilder.String(),
		ShouldReturn: false,
		Err:          nil,
	}
}

// handleAction 处理 Action 事件
func (e *EventHandler) handleAction(
	sessionID, checkPointID string,
	action *adk.AgentAction,
	contentBuilder *strings.Builder,
) *ProcessResult {
	// 1. 中断处理
	if action.Interrupted != nil {
		return e.handleInterrupt(sessionID, checkPointID, action.Interrupted)
	}

	// 2. Agent 转移
	if action.TransferToAgent != nil {
		e.output.PrintTransfer(action.TransferToAgent)
		return &ProcessResult{ShouldReturn: false}
	}

	// 3. 退出
	if action.Exit {
		e.output.PrintExit()
		e.state.SetState(StateExited)
		return &ProcessResult{ShouldReturn: true}
	}

	// 4. BreakLoop
	if action.BreakLoop != nil {
		e.output.PrintBreakLoop()
		return &ProcessResult{ShouldReturn: false}
	}

	// 5. 自定义 Action
	if action.CustomizedAction != nil {
		fmt.Printf("  ⚙️ [CustomAction] %v\n", action.CustomizedAction)
		return &ProcessResult{ShouldReturn: false}
	}

	return &ProcessResult{ShouldReturn: false}
}

// handleInterrupt 处理中断
func (e *EventHandler) handleInterrupt(
	sessionID, checkPointID string,
	info *adk.InterruptInfo,
) *ProcessResult {
	if len(info.InterruptContexts) == 0 {
		return &ProcessResult{
			ShouldReturn: true,
			Err:          fmt.Errorf("interrupt info has no contexts"),
		}
	}

	ic := info.InterruptContexts[0]
	interruptID := ic.ID
	interruptInfo := ic.Info

	// 解析中断信息
	prompt, interruptType := e.parseInterruptInfo(interruptInfo)

	// 打印中断信息
	ictx := &InterruptContext{
		CheckPointID: checkPointID,
		InterruptID:  interruptID,
		Info:         interruptInfo,
		SessionID:    sessionID,
		Prompt:       prompt,
		Type:         interruptType,
	}
	e.output.PrintInterrupt(ictx)

	// 保存中断上下文
	e.state.SetInterruptContext(ictx)

	return &ProcessResult{ShouldReturn: true}
}

// parseInterruptInfo 解析中断信息
func (e *EventHandler) parseInterruptInfo(info any) (prompt, interruptType string) {
	switch v := info.(type) {
	case string:
		prompt = v
		interruptType = "clarification"
	case *ApprovalRequest:
		interruptType = "approval"
		prompt = v.Message
	case map[string]any:
		if msg, ok := v["message"].(string); ok {
			prompt = msg
		}
		if t, ok := v["type"].(string); ok {
			interruptType = t
		}
	default:
		prompt = fmt.Sprintf("%v", info)
		interruptType = "unknown"
	}
	return prompt, interruptType
}

// convertMessageVariant 转换消息变体
func (e *EventHandler) convertMessageVariant(mv *adk.MessageVariant) *MessageVariant {
	return &MessageVariant{
		Role:          mv.Role,
		IsStreaming:   mv.IsStreaming,
		Message:       mv.Message,
		MessageStream: mv.MessageStream,
		ToolName:      mv.ToolName,
	}
}
