package agent

import (
	"context"
	"fmt"
	"log"

	"github.com/cloudwego/eino/adk"
	"github.com/cloudwego/eino/components/tool"
	"github.com/cloudwego/eino/schema"

	"my-eino-agent/internal/config"
	"my-eino-agent/internal/session"
)

// Runner 封装的 Agent Runner（精简版）
type Runner struct {
	runner   *adk.Runner
	cfg      *config.Config
	sessions *session.Manager

	// 模块化组件
	state   *StateManager
	output  *OutputHandler
	events  *EventHandler
}

// NewRunner 创建 Runner
func NewRunner(cfg *config.Config, agent adk.Agent, sessionManager *session.Manager) *Runner {
	state := NewStateManager()
	output := NewOutputHandler(true) // verbose mode

	return &Runner{
		runner: adk.NewRunner(context.Background(), adk.RunnerConfig{
			Agent:           agent,
			EnableStreaming: cfg.Server.EnableStreaming,
		}),
		cfg:      cfg,
		sessions: sessionManager,
		state:     state,
		output:    output,
		events:    NewEventHandler(state, output),
	}
}

// ========================================
// 核心 API
// ========================================

// Query 执行查询
func (r *Runner) Query(ctx context.Context, sessionID, query string) (string, error) {
	// 检查中断状态
	if r.state.IsInterrupted() {
		return "", fmt.Errorf("runner is interrupted, please use Resume() or Cancel()")
	}

	r.state.SetState(StateRunning)
	r.output.PrintUserInput(sessionID, query)

	// 获取会话并添加用户消息
	sess, err := r.sessions.GetOrCreate(ctx, sessionID)
	if err != nil {
		r.state.SetState(StateIdle)
		return "", fmt.Errorf("failed to get session: %w", err)
	}

	userMsg := schema.UserMessage(query)
	if err := r.sessions.AddMessage(ctx, sessionID, userMsg); err != nil {
		log.Printf("Warning: failed to add user message: %v", err)
	}

	// 执行 Agent
	history := sess.Messages
	allMsgs := append(history, userMsg)
	checkPointID := fmt.Sprintf("cp-%s", sessionID)
	iter := r.runner.Run(ctx, allMsgs, adk.WithCheckPointID(checkPointID))

	// 处理事件流
	result := r.events.ProcessEventStream(sessionID, checkPointID, iter)

	// 检查是否在中断状态
	if r.state.IsInterrupted() {
		return result.Content, result.Err
	}

	// 保存消息
	if result.Content != "" {
		r.saveAssistantMessage(ctx, sessionID, result.Content)
	}

	r.state.SetState(StateIdle)
	return result.Content, result.Err
}

// Resume 恢复中断的执行
func (r *Runner) Resume(ctx context.Context, userInput string) (string, error) {
	ictx := r.state.GetInterruptContext()
	if ictx == nil {
		return "", fmt.Errorf("no interrupt context found")
	}

	r.output.PrintUserInput(ictx.SessionID, userInput)

	params := &adk.ResumeParams{
		Targets: map[string]any{
			ictx.InterruptID: userInput,
		},
	}

	r.state.SetState(StateRunning)
	r.state.ClearInterruptContext()

	iter, err := r.runner.ResumeWithParams(ctx, ictx.CheckPointID, params)
	if err != nil {
		r.state.SetState(StateInterrupted)
		return "", fmt.Errorf("failed to resume: %w", err)
	}

	result := r.events.ProcessEventStream(ictx.SessionID, ictx.CheckPointID, iter)

	if !r.state.IsInterrupted() && result.Content != "" {
		r.saveAssistantMessage(ctx, ictx.SessionID, result.Content)
	}

	r.state.SetState(StateIdle)
	return result.Content, result.Err
}

// ResumeWithApproval 恢复执行并批准工具调用
func (r *Runner) ResumeWithApproval(ctx context.Context, approved bool, modifiedInput any) (string, error) {
	ictx := r.state.GetInterruptContext()
	if ictx == nil {
		return "", fmt.Errorf("no interrupt context found")
	}

	approvalResult := &tool.ApprovalResult{
		Approved:      approved,
		ModifiedInput: modifiedInput,
	}

	r.output.PrintApprovalDecision(approved)

	params := &adk.ResumeParams{
		Targets: map[string]any{
			ictx.InterruptID: approvalResult,
		},
	}

	r.state.SetState(StateRunning)
	r.state.ClearInterruptContext()

	iter, err := r.runner.ResumeWithParams(ctx, ictx.CheckPointID, params)
	if err != nil {
		r.state.SetState(StateInterrupted)
		return "", fmt.Errorf("failed to resume: %w", err)
	}

	result := r.events.ProcessEventStream(ictx.SessionID, ictx.CheckPointID, iter)

	if !r.state.IsInterrupted() && result.Content != "" {
		r.saveAssistantMessage(ctx, ictx.SessionID, result.Content)
	}

	r.state.SetState(StateIdle)
	return result.Content, result.Err
}

// Cancel 取消中断状态
func (r *Runner) Cancel() {
	r.state.ClearInterruptContext()
	r.state.SetState(StateIdle)
	r.output.PrintCancel()
}

// ========================================
// 状态查询
// ========================================

func (r *Runner) GetState() RunnerState {
	return r.state.GetState()
}

func (r *Runner) IsInterrupted() bool {
	return r.state.IsInterrupted()
}

func (r *Runner) GetInterruptContext() *InterruptContext {
	return r.state.GetInterruptContext()
}

// ========================================
// 会话管理
// ========================================

func (r *Runner) GetSessionHistory(ctx context.Context, sessionID string) ([]*schema.Message, error) {
	return r.sessions.GetMessages(ctx, sessionID)
}

func (r *Runner) ClearSession(ctx context.Context, sessionID string) error {
	return r.sessions.Clear(ctx, sessionID)
}

func (r *Runner) ListSessions() []string {
	return r.sessions.List()
}

func (r *Runner) GetSessionManager() *session.Manager {
	return r.sessions
}

// ========================================
// 内部方法
// ========================================

func (r *Runner) saveAssistantMessage(ctx context.Context, sessionID, content string) {
	assistantMsg := schema.AssistantMessage(content, nil)
	if err := r.sessions.AddMessage(ctx, sessionID, assistantMsg); err != nil {
		log.Printf("Warning: failed to add assistant message: %v", err)
	}
	if err := r.sessions.Save(ctx, sessionID); err != nil {
		log.Printf("Warning: failed to save session: %v", err)
	}
}
