## 4. internal/agent/handlers.go

```go
package agent

import (
	"errors"
	"fmt"
	"io"
	"strings"

	"github.com/cloudwego/eino/adk"
	"github.com/cloudwego/eino/components/tool"
	"github.com/cloudwego/eino/schema"
)

// processEventStream 处理事件流，返回累积的文本内容
func processEventStream(state *StateManager, iter *adk.AsyncIterator[*adk.AgentEvent]) (string, error) {
	var content strings.Builder

	for {
		event, ok := iter.Next()
		if !ok {
			break
		}

		if event.Err != nil {
			printError(event.Err)
			return content.String(), event.Err
		}

		// Action 处理（可能设置中断状态）
		if event.Action != nil {
			if handleAction(state, event.Action) {
				return content.String(), nil // 中断时返回
			}
			continue
		}

		// 消息处理
		if event.Output != nil && event.Output.MessageOutput != nil {
			text := handleMessageOutput(event.Output.MessageOutput)
			content.WriteString(text)
		}
	}

	return content.String(), nil
}

// handleAction 处理 Action，返回 true 表示需要中断
func handleAction(state *StateManager, action *adk.AgentAction) bool {
	if action.Interrupted != nil {
		return handleInterrupt(state, action.Interrupted)
	}
	if action.TransferToAgent != nil {
		printTransfer(action.TransferToAgent.DestAgentName)
		return false
	}
	if action.Exit {
		printExit()
		return true
	}
	return false
}

// handleInterrupt 解析并设置中断上下文
func handleInterrupt(state *StateManager, info *adk.InterruptInfo) bool {
	if len(info.InterruptContexts) == 0 {
		return false
	}

	ic := info.InterruptContexts[0]
	prompt, typ := parseInterruptInfo(ic.Info)

	ctx := &InterruptContext{
		CheckPointID: info.CheckPointID,
		InterruptID:  ic.ID,
		SessionID:    "", // 由调用者设置
		Prompt:       prompt,
		Type:         typ,
	}
	state.SetInterrupt(ctx)
	printInterrupt(ctx)
	return true
}

// parseInterruptInfo 解析中断信息
func parseInterruptInfo(info any) (prompt, typ string) {
	switch v := info.(type) {
	case string:
		return v, "clarification"
	case map[string]any:
		if msg, ok := v["message"].(string); ok {
			prompt = msg
		}
		if t, ok := v["type"].(string); ok {
			typ = t
		}
		return prompt, typ
	default:
		return fmt.Sprintf("%v", info), "unknown"
	}
}

// handleMessageOutput 处理消息输出，返回文本内容
func handleMessageOutput(mv *adk.MessageVariant) string {
	if mv.Role == schema.Tool {
		result := drainToolResult(mv)
		printToolResult(mv.ToolName, result)
		return "" // 工具结果不保存
	}

	if mv.Role == schema.Assistant {
		if mv.IsStreaming {
			return handleStreamingMessage(mv)
		}
		return handleNonStreamingMessage(mv)
	}
	return ""
}

// handleStreamingMessage 处理流式消息
func handleStreamingMessage(mv *adk.MessageVariant) string {
	mv.MessageStream.SetAutomaticClose()

	var text strings.Builder
	printAssistantPrefix()

	for {
		chunk, err := mv.MessageStream.Recv()
		if errors.Is(err, io.EOF) {
			break
		}
		if err != nil {
			printError(err)
			break
		}
		if chunk != nil && chunk.Content != "" {
			printAssistantText(chunk.Content)
			text.WriteString(chunk.Content)
		}
	}

	printAssistantNewLine()
	return text.String()
}

// handleNonStreamingMessage 处理非流式消息
func handleNonStreamingMessage(mv *adk.MessageVariant) string {
	if mv.Message == nil {
		return ""
	}
	printAssistantPrefix()
	printAssistantText(mv.Message.Content)
	printAssistantNewLine()
	return mv.Message.Content
}

// drainToolResult 消费工具结果
func drainToolResult(mv *adk.MessageVariant) string {
	if mv.IsStreaming && mv.MessageStream != nil {
		var sb strings.Builder
		for {
			chunk, err := mv.MessageStream.Recv()
			if errors.Is(err, io.EOF) {
				break
			}
			if err != nil || chunk == nil {
				break
			}
			sb.WriteString(chunk.Content)
		}
		return sb.String()
	}
	if mv.Message != nil {
		return mv.Message.Content
	}
	return ""
}

// buildResumeParams 构建恢复参数
func buildResumeParams(interruptID string, value any) *adk.ResumeParams {
	return &adk.ResumeParams{
		Targets: map[string]any{interruptID: value},
	}
}

// buildApprovalResult 构建批准结果
func buildApprovalResult(approved bool, modifiedInput any) *tool.ApprovalResult {
	return &tool.ApprovalResult{
		Approved:      approved,
		ModifiedInput: modifiedInput,
	}
}
