```go
package agent

import "sync"

type StateManager struct {
	mu           sync.RWMutex
	state        RunnerState
	interruptCtx *InterruptContext
}

func NewStateManager() *StateManager {
	return &StateManager{state: StateIdle}
}

func (s *StateManager) GetState() RunnerState {
	s.mu.RLock()
	defer s.mu.RUnlock()
	return s.state
}

func (s *StateManager) SetState(state RunnerState) {
	s.mu.Lock()
	s.state = state
	s.mu.Unlock()
}

func (s *StateManager) IsInterrupted() bool { return s.GetState() == StateInterrupted }

func (s *StateManager) GetInterruptContext() *InterruptContext {
	s.mu.RLock()
	defer s.mu.RUnlock()
	return s.interruptCtx
}

func (s *StateManager) SetInterrupt(ctx *InterruptContext) {
	s.mu.Lock()
	s.state = StateInterrupted
	s.interruptCtx = ctx
	s.mu.Unlock()
}

func (s *StateManager) ClearInterrupt() {
	s.mu.Lock()
	s.interruptCtx = nil
	s.state = StateIdle
	s.mu.Unlock()
}
