package agent

import "fmt"

func printUser(sessionID, input string) {
	fmt.Printf("\n[Session: %s] 👤 用户: %s\n", sessionID, input)
}

func printAssistant(text string) { fmt.Printf("🤖 助手: %s\n", text) }
func printAssistantStream(text string) { fmt.Print(text) }
func printAssistantEnd() { fmt.Println() }

func printToolCall(name, args string) {
	fmt.Printf("  🔧 [工具] %s(%s)\n", name, truncate(args, 60))
}

func printToolResult(name, result string) {
	fmt.Printf("  ✅ [结果] %s: %s\n", name, truncate(result, 150))
}

func printInterrupt(ctx *InterruptContext) {
	fmt.Printf("\n  ⏸️ [中断] %s: %s\n", ctx.Type, ctx.Prompt)
	if ctx.Type == "approval" {
		fmt.Println("  → /approve | /reject | /cancel")
	}
}

func printTransfer(dest string) { fmt.Printf("  ➡️ [转移] %s\n", dest) }
func printExit() { fmt.Println("  🏁 [结束]") }
func printCancel() { fmt.Println("⚠️ 已取消") }
func printApproval(ok bool) {
	if ok { fmt.Println("✅ 已批准") } else { fmt.Println("❌ 已拒绝") }
}
func printError(err error) { fmt.Printf("  ❌ [错误] %v\n", err) }

func truncate(s string, n int) string {
	if len(s) <= n { return s }
	return s[:n] + "..."
}
