## 4. internal/agent/runner.go

```go
package agent

import (
	"context"
	"errors"
	"fmt"
	"io"
	"log"
	"strings"

	"github.com/cloudwego/eino/adk"
	"github.com/cloudwego/eino/components/tool"
	"github.com/cloudwego/eino/schema"

	"my-eino-agent/internal/config"
	"my-eino-agent/internal/session"
)

type Runner struct {
	runner   *adk.Runner
	sessions *session.Manager
	state    *StateManager
}

func NewRunner(cfg *config.Config, agent adk.Agent, sm *session.Manager) *Runner {
	return &Runner{
		runner: adk.NewRunner(context.Background(), adk.RunnerConfig{
			Agent:           agent,
			EnableStreaming: cfg.Server.EnableStreaming,
		}),
		sessions: sm,
		state:    NewStateManager(),
	}
}

// ========================================
// 公开 API
// ========================================

func (r *Runner) Query(ctx context.Context, sessionID, query string) (string, error) {
	if r.state.IsInterrupted() {
		return "", fmt.Errorf("已中断，请使用 Resume 或 Cancel")
	}

	r.state.SetState(StateRunning)
	printUser(sessionID, query)

	// 会话 + 用户消息
	sess, _ := r.sessions.GetOrCreate(ctx, sessionID)
	userMsg := schema.UserMessage(query)
	r.sessions.AddMessage(ctx, sessionID, userMsg)

	// 执行
	cpID := fmt.Sprintf("cp-%s", sessionID)
	iter := r.runner.Run(ctx, append(sess.Messages, userMsg), adk.WithCheckPointID(cpID))

	content, err := r.processStream(iter, sessionID, cpID)

	// 保存
	if !r.state.IsInterrupted() && content != "" {
		r.sessions.AddMessage(ctx, sessionID, schema.AssistantMessage(content, nil))
		r.sessions.Save(ctx, sessionID)
	}

	r.state.SetState(StateIdle)
	return content, err
}

func (r *Runner) Resume(ctx context.Context, input string) (string, error) {
	ictx := r.state.GetInterruptContext()
	if ictx == nil {
		return "", fmt.Errorf("无中断上下文")
	}

	printUser(ictx.SessionID, input)
	r.state.ClearInterrupt()
	r.state.SetState(StateRunning)

	params := &adk.ResumeParams{Targets: map[string]any{ictx.InterruptID: input}}
	iter, err := r.runner.ResumeWithParams(ctx, ictx.CheckPointID, params)
	if err != nil {
		r.state.SetInterrupt(ictx)
		return "", err
	}

	content, err := r.processStream(iter, ictx.SessionID, ictx.CheckPointID)

	if !r.state.IsInterrupted() && content != "" {
		r.sessions.AddMessage(ctx, ictx.SessionID, schema.AssistantMessage(content, nil))
		r.sessions.Save(ctx, ictx.SessionID)
	}

	r.state.SetState(StateIdle)
	return content, err
}

func (r *Runner) ResumeWithApproval(ctx context.Context, approved bool, modified any) (string, error) {
	ictx := r.state.GetInterruptContext()
	if ictx == nil {
		return "", fmt.Errorf("无中断上下文")
	}

	printApproval(approved)
	r.state.ClearInterrupt()
	r.state.SetState(StateRunning)

	result := &tool.ApprovalResult{Approved: approved, ModifiedInput: modified}
	params := &adk.ResumeParams{Targets: map[string]any{ictx.InterruptID: result}}
	iter, err := r.runner.ResumeWithParams(ctx, ictx.CheckPointID, params)
	if err != nil {
		r.state.SetInterrupt(ictx)
		return "", err
	}

	content, err := r.processStream(iter, ictx.SessionID, ictx.CheckPointID)

	if !r.state.IsInterrupted() && content != "" {
		r.sessions.AddMessage(ctx, ictx.SessionID, schema.AssistantMessage(content, nil))
		r.sessions.Save(ctx, ictx.SessionID)
	}

	r.state.SetState(StateIdle)
	return content, err
}

func (r *Runner) Cancel() { r.state.ClearInterrupt(); printCancel() }

// ========================================
// 状态查询
// ========================================

func (r *Runner) GetState() RunnerState { return r.state.GetState() }
func (r *Runner) IsInterrupted() bool    { return r.state.IsInterrupted() }
func (r *Runner) GetInterruptContext() *InterruptContext { return r.state.GetInterruptContext() }

// ========================================
// 会话管理
// ========================================

func (r *Runner) GetHistory(ctx context.Context, sid string) ([]*schema.Message, error) {
	return r.sessions.GetMessages(ctx, sid)
}
func (r *Runner) ClearSession(ctx context.Context, sid string) error {
	return r.sessions.Clear(ctx, sid)
}
func (r *Runner) ListSessions() []string { return r.sessions.List() }

// ========================================
// 内部：事件处理
// ========================================

func (r *Runner) processStream(iter *adk.AsyncIterator[*adk.AgentEvent], sessionID, cpID string) (string, error) {
	var content strings.Builder

	for {
		event, ok := iter.Next()
		if !ok {
			break
		}

		if event.Err != nil {
			printError(event.Err)
			return content.String(), event.Err
		}

		// Action 处理
		if event.Action != nil {
			if r.handleAction(event.Action, sessionID, cpID) {
				return content.String(), nil
			}
			continue
		}

		// 消息处理
		if event.Output != nil && event.Output.MessageOutput != nil {
			content.WriteString(r.handleMessage(event.Output.MessageOutput))
		}
	}

	return content.String(), nil
}

func (r *Runner) handleAction(action *adk.AgentAction, sessionID, cpID string) bool {
	// 中断
	if action.Interrupted != nil {
		ic := action.Interrupted.InterruptContexts[0]
		prompt, typ := parseInterruptInfo(ic.Info)
		ctx := &InterruptContext{
			CheckPointID: cpID,
			InterruptID:  ic.ID,
			SessionID:    sessionID,
			Prompt:       prompt,
			Type:         typ,
		}
		r.state.SetInterrupt(ctx)
		printInterrupt(ctx)
		return true
	}

	// 转移
	if action.TransferToAgent != nil {
		printTransfer(action.TransferToAgent.DestAgentName)
		return false
	}

	// 退出
	if action.Exit {
		printExit()
		return true
	}

	return false
}

func parseInterruptInfo(info any) (prompt, typ string) {
	switch v := info.(type) {
	case string:
		return v, "clarification"
	case map[string]any:
		if msg, ok := v["message"].(string); ok { prompt = msg }
		if t, ok := v["type"].(string); ok { typ = t }
		return prompt, typ
	default:
		return fmt.Sprintf("%v", info), "unknown"
	}
}

// ========================================
// 内部：消息处理
// ========================================

func (r *Runner) handleMessage(mv *adk.MessageVariant) string {
	// Tool 消息
	if mv.Role == schema.Tool {
		result := r.drainTool(mv)
		printToolResult(mv.ToolName, result)
		return ""
	}

	// Assistant 消息
	if mv.Role == schema.Assistant {
		if mv.IsStreaming {
			return r.handleStreamMsg(mv)
		}
		return r.handleStaticMsg(mv)
	}
	return ""
}

func (r *Runner) handleStreamMsg(mv *adk.MessageVariant) string {
	mv.MessageStream.SetAutomaticClose()
	var text strings.Builder

	fmt.Print("🤖 助手: ")
	for {
		chunk, err := mv.MessageStream.Recv()
		if errors.Is(err, io.EOF) {
			break
		}
		if err != nil || chunk == nil {
			break
		}
		if chunk.Content != "" {
			printAssistantStream(chunk.Content)
			text.WriteString(chunk.Content)
		}
	}
	fmt.Println()
	return text.String()
}

func (r *Runner) handleStaticMsg(mv *adk.MessageVariant) string {
	if mv.Message == nil { return "" }
	printAssistant(mv.Message.Content)
	return mv.Message.Content
}

func (r *Runner) drainTool(mv *adk.MessageVariant) string {
	if mv.IsStreaming && mv.MessageStream != nil {
		var sb strings.Builder
		for {
			chunk, err := mv.MessageStream.Recv()
			if errors.Is(err, io.EOF) || err != nil || chunk == nil {
				break
			}
			sb.WriteString(chunk.Content)
		}
		return sb.String()
	}
	if mv.Message != nil {
		return mv.Message.Content
	}
	return ""
}
